const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider      = \"prisma-client-js\"\n  output        = \"../generated/prisma\"\n  binaryTargets = [\"native\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum ModuleDomain {\n  MATH\n  SCIENCE\n  TECH\n  ENGINEERING\n  MEDICINE\n  HEALTH\n  BUSINESS\n  MANAGEMENT\n  ECONOMICS\n  COMPUTER_SCIENCE\n  INTERDISCIPLINARY\n}\n\nenum ReviewStatus {\n  PENDING\n  IN_REVIEW\n  APPROVED\n  REJECTED\n  CHANGES_REQUESTED\n}\n\nenum ReviewPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\nenum StripeAccountStatus {\n  PENDING\n  ONBOARDING\n  ENABLED\n  RESTRICTED\n  DISABLED\n}\n\nenum ModuleDifficulty {\n  INTRO\n  INTERMEDIATE\n  ADVANCED\n}\n\nenum ModuleStatus {\n  DRAFT\n  PUBLISHED\n  ARCHIVED\n}\n\nenum EnrollmentStatus {\n  NOT_STARTED\n  IN_PROGRESS\n  COMPLETED\n}\n\nenum AssessmentType {\n  QUIZ\n  PROJECT\n  SIMULATION\n}\n\nenum AssessmentStatus {\n  DRAFT\n  PUBLISHED\n  ARCHIVED\n}\n\nenum AssessmentAttemptStatus {\n  IN_PROGRESS\n  SUBMITTED\n  GRADED\n  EXPIRED\n}\n\nenum LearnerDifficultyPreference {\n  BEGINNER\n  EASY\n  MEDIUM\n  HARD\n  EXPERT\n}\n\nenum LearnerModalityPreference {\n  VISUAL\n  AUDITORY\n  KINESTHETIC\n  READING\n  MIXED\n}\n\nenum LearnerPacingPreference {\n  SELF_PACED\n  GUIDED\n  ADAPTIVE\n  INTENSIVE\n}\n\nenum KnowledgeGapSeverity {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum KnowledgeGapDetectionMethod {\n  ASSESSMENT\n  PREREQUISITE_CHECK\n  ADAPTIVE_ANALYSIS\n  LEARNER_REPORTED\n  AI_PREDICTION\n}\n\n// =============================================================================\n// Evidence Layer Enums (Phase 1)\n// =============================================================================\n\nenum EvidenceSourceType {\n  OPENSTAX\n  KHAN_ACADEMY\n  WIKIPEDIA\n  PEER_REVIEWED_JOURNAL\n  TEXTBOOK\n  CURRICULUM_STANDARD\n  DOMAIN_EXPERT\n  SIMULATION_RESULT\n  CALCULATION\n}\n\nenum SupportKind {\n  SUPPORTS\n  CONTRADICTS\n  NEUTRAL\n  PARTIALLY_SUPPORTS\n}\n\nenum EvidenceFreshnessStatus {\n  CURRENT\n  STALE\n  EXPIRED\n  UNKNOWN\n}\n\nenum EvidenceVerificationState {\n  UNVERIFIED\n  VERIFIED\n  DISPUTED\n  FAILED_VERIFICATION\n}\n\nenum LearnerPathwayStatus {\n  DRAFT\n  ACTIVE\n  PAUSED\n  COMPLETED\n  ABANDONED\n}\n\nenum ListingStatus {\n  DRAFT\n  ACTIVE\n  ARCHIVED\n}\n\nenum ListingVisibility {\n  PUBLIC\n  PRIVATE\n}\n\nmodel Module {\n  id                   String           @id @default(cuid())\n  tenantId             String\n  slug                 String\n  title                String\n  domain               ModuleDomain\n  difficulty           ModuleDifficulty\n  estimatedTimeMinutes Int\n  status               ModuleStatus     @default(PUBLISHED)\n  description          String\n  version              Int              @default(1)\n  authorId             String?\n  updatedBy            String?\n  publishedAt          DateTime?\n  deletedAt            DateTime?\n  createdAt            DateTime         @default(now())\n  updatedAt            DateTime         @updatedAt\n\n  tags                ModuleTag[]\n  learningObjectives  ModuleLearningObjective[]\n  contentBlocks       ModuleContentBlock[]\n  prerequisites       ModulePrerequisite[]      @relation(\"ModulePrerequisites\")\n  requiredBy          ModulePrerequisite[]      @relation(\"ModuleDependents\")\n  enrollments         Enrollment[]\n  revisions           ModuleRevision[]\n  marketplaceListings MarketplaceListing[]\n  assessments         Assessment[]\n  simulationTemplates SimulationTemplate[]\n  simulationManifests SimulationManifest[]\n  animationManifests  AnimationManifest[]\n  learningExperience  LearningExperience?\n\n  @@unique([tenantId, slug])\n  @@index([tenantId, domain])\n  @@index([tenantId, status])\n  @@index([tenantId, createdAt])\n  @@index([tenantId, publishedAt])\n  @@index([tenantId, updatedAt])\n  @@index([tenantId, status, domain])\n  @@index([tenantId, status, difficulty])\n  @@index([tenantId, deletedAt])\n}\n\nmodel ModuleTag {\n  id       Int    @id @default(autoincrement())\n  module   Module @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId String\n  label    String\n\n  @@unique([moduleId, label])\n}\n\nmodel ModuleLearningObjective {\n  id            Int    @id @default(autoincrement())\n  module        Module @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId      String\n  label         String\n  taxonomyLevel String\n}\n\nmodel ModuleContentBlock {\n  id         String @id @default(cuid())\n  module     Module @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId   String\n  orderIndex Int\n  blockType  String\n  payload    Json\n}\n\nmodel ModulePrerequisite {\n  module               Module @relation(\"ModulePrerequisites\", fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId             String\n  prerequisite         Module @relation(\"ModuleDependents\", fields: [prerequisiteModuleId], references: [id], onDelete: Cascade)\n  prerequisiteModuleId String\n\n  @@id([moduleId, prerequisiteModuleId])\n}\n\nmodel ModuleRevision {\n  id        String   @id @default(cuid())\n  module    Module   @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId  String\n  version   Int\n  snapshot  Json\n  createdBy String\n  createdAt DateTime @default(now())\n\n  @@index([moduleId, version])\n}\n\nmodel Enrollment {\n  id               String           @id @default(cuid())\n  tenantId         String\n  userId           String\n  module           Module           @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId         String\n  status           EnrollmentStatus @default(NOT_STARTED)\n  progressPercent  Int              @default(0)\n  startedAt        DateTime?\n  completedAt      DateTime?\n  timeSpentSeconds Int              @default(0)\n  deletedAt        DateTime?\n  createdAt        DateTime         @default(now())\n  updatedAt        DateTime         @updatedAt\n\n  @@unique([tenantId, userId, moduleId])\n  @@index([tenantId, userId])\n  @@index([tenantId, status])\n  @@index([tenantId, createdAt])\n  @@index([tenantId, startedAt])\n  @@index([tenantId, completedAt])\n  @@index([tenantId, status, moduleId])\n  @@index([tenantId, deletedAt])\n}\n\nmodel Assessment {\n  id               String           @id @default(cuid())\n  tenantId         String\n  module           Module           @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId         String\n  title            String\n  type             AssessmentType   @default(QUIZ)\n  status           AssessmentStatus @default(DRAFT)\n  version          Int              @default(1)\n  passingScore     Int              @default(80)\n  attemptsAllowed  Int?\n  timeLimitMinutes Int?\n  createdBy        String\n  updatedBy        String\n  createdAt        DateTime         @default(now())\n  updatedAt        DateTime         @updatedAt\n\n  objectives AssessmentObjective[]\n  items      AssessmentItem[]\n  attempts   AssessmentAttempt[]\n\n  @@index([tenantId, moduleId])\n  @@index([tenantId, status])\n  @@index([tenantId, createdAt])\n  @@index([tenantId, updatedAt])\n  @@index([tenantId, status, type])\n}\n\nmodel AssessmentObjective {\n  id            String     @id @default(cuid())\n  assessment    Assessment @relation(fields: [assessmentId], references: [id], onDelete: Cascade)\n  assessmentId  String\n  label         String\n  taxonomyLevel String\n}\n\nmodel AssessmentItem {\n  id           String     @id @default(cuid())\n  assessment   Assessment @relation(fields: [assessmentId], references: [id], onDelete: Cascade)\n  assessmentId String\n  orderIndex   Int\n  itemType     String\n  prompt       String\n  stimulus     String?\n  choices      Json?\n  modelAnswer  String?\n  rubric       String?\n  points       Int        @default(10)\n  metadata     Json?\n}\n\nmodel AssessmentAttempt {\n  id               String                  @id @default(cuid())\n  tenantId         String\n  assessment       Assessment              @relation(fields: [assessmentId], references: [id], onDelete: Cascade)\n  assessmentId     String\n  userId           String\n  status           AssessmentAttemptStatus @default(IN_PROGRESS)\n  responses        Json?\n  scorePercent     Int?\n  feedback         Json?\n  startedAt        DateTime                @default(now())\n  submittedAt      DateTime?\n  gradedAt         DateTime?\n  timeSpentSeconds Int?\n\n  @@index([tenantId, userId])\n  @@index([tenantId, assessmentId])\n}\n\nmodel AssessmentDraft {\n  id        String   @id @default(cuid())\n  tenantId  String\n  moduleId  String\n  createdBy String\n  payload   Json\n  createdAt DateTime @default(now())\n\n  @@index([tenantId, moduleId])\n  @@index([tenantId, createdBy])\n}\n\nmodel LearningEvent {\n  id        String   @id @default(cuid())\n  tenantId  String\n  userId    String\n  moduleId  String?\n  eventType String\n  payload   Json?\n  timestamp DateTime @default(now())\n\n  @@index([tenantId, eventType])\n  @@index([tenantId, userId])\n  @@index([tenantId, timestamp])\n}\n\nmodel MarketplaceListing {\n  id          String            @id @default(cuid())\n  tenantId    String\n  module      Module            @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n  moduleId    String\n  creatorId   String\n  priceCents  Int               @default(0)\n  status      ListingStatus     @default(DRAFT)\n  visibility  ListingVisibility @default(PUBLIC)\n  publishedAt DateTime?\n  createdAt   DateTime          @default(now())\n  updatedAt   DateTime          @updatedAt\n\n  @@index([tenantId, status])\n  @@index([tenantId, moduleId])\n  @@index([tenantId, creatorId])\n  @@index([tenantId, createdAt])\n  @@index([tenantId, publishedAt])\n}\n\n// =============================================================================\n// Learning Pathways\n// =============================================================================\n\nenum PathwayStatus {\n  ACTIVE\n  COMPLETED\n  PAUSED\n}\n\nmodel LearningPath {\n  id        String        @id @default(cuid())\n  tenantId  String\n  userId    String\n  title     String\n  goal      String\n  status    PathwayStatus @default(ACTIVE)\n  deletedAt DateTime?\n  createdAt DateTime      @default(now())\n  updatedAt DateTime      @updatedAt\n\n  nodes LearningPathNode[]\n\n  @@unique([tenantId, userId, status])\n  @@index([tenantId, userId])\n}\n\nmodel LearningPathNode {\n  id          String       @id @default(cuid())\n  pathId      String\n  path        LearningPath @relation(fields: [pathId], references: [id], onDelete: Cascade)\n  moduleId    String\n  orderIndex  Int\n  isOptional  Boolean      @default(false)\n  completedAt DateTime?\n\n  @@unique([pathId, moduleId])\n  @@index([pathId])\n}\n\n// =============================================================================\n// Teacher/Classroom\n// =============================================================================\n\nmodel Classroom {\n  id          String    @id @default(cuid())\n  tenantId    String\n  teacherId   String\n  name        String\n  description String?\n  deletedAt   DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  roster      ClassroomStudent[]\n  assignments ClassroomAssignment[]\n\n  @@index([tenantId, teacherId])\n  @@index([tenantId, deletedAt])\n}\n\nmodel ClassroomStudent {\n  id          String    @id @default(cuid())\n  classroomId String\n  classroom   Classroom @relation(fields: [classroomId], references: [id], onDelete: Cascade)\n  userId      String\n  displayName String\n  email       String?\n  enrolledAt  DateTime  @default(now())\n\n  @@unique([classroomId, userId])\n  @@index([classroomId])\n}\n\nmodel ClassroomAssignment {\n  id          String    @id @default(cuid())\n  classroomId String\n  classroom   Classroom @relation(fields: [classroomId], references: [id], onDelete: Cascade)\n  moduleId    String\n  assignedAt  DateTime  @default(now())\n  dueAt       DateTime?\n\n  @@unique([classroomId, moduleId])\n  @@index([classroomId])\n}\n\n// =============================================================================\n// Collaboration (Q&A, Discussions)\n// =============================================================================\n\nenum ThreadStatus {\n  OPEN\n  RESOLVED\n  CLOSED\n}\n\nmodel Thread {\n  id         String       @id @default(cuid())\n  tenantId   String\n  moduleId   String?\n  title      String\n  status     ThreadStatus @default(OPEN)\n  authorId   String\n  authorName String\n  createdAt  DateTime     @default(now())\n  resolvedAt DateTime?\n\n  posts Post[]\n\n  @@index([tenantId, moduleId])\n  @@index([tenantId, status])\n  @@index([tenantId, authorId])\n}\n\nmodel Post {\n  id         String   @id @default(cuid())\n  threadId   String\n  thread     Thread   @relation(fields: [threadId], references: [id], onDelete: Cascade)\n  authorId   String\n  authorName String\n  content    String\n  isAnswer   Boolean  @default(false)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([threadId])\n}\n\nenum HelpRequestStatus {\n  PENDING\n  ANSWERED\n  ESCALATED\n}\n\nmodel HelpRequest {\n  id         String            @id @default(cuid())\n  tenantId   String\n  userId     String\n  moduleId   String\n  question   String\n  status     HelpRequestStatus @default(PENDING)\n  createdAt  DateTime          @default(now())\n  answeredAt DateTime?\n\n  @@index([tenantId, status])\n  @@index([tenantId, userId])\n}\n\n// =============================================================================\n// Billing/Payments\n// =============================================================================\n\nenum CheckoutStatus {\n  PENDING\n  COMPLETED\n  FAILED\n  CANCELLED\n}\n\nmodel CheckoutSession {\n  id              String         @id @default(cuid())\n  tenantId        String\n  userId          String\n  listingId       String\n  amountCents     Int\n  status          CheckoutStatus @default(PENDING)\n  paymentUrl      String?\n  stripeSessionId String?\n  successUrl      String?\n  cancelUrl       String?\n  createdAt       DateTime       @default(now())\n  completedAt     DateTime?\n\n  @@index([tenantId, userId])\n  @@index([tenantId, status])\n}\n\nmodel Purchase {\n  id          String   @id @default(cuid())\n  tenantId    String\n  userId      String\n  listingId   String\n  moduleId    String\n  amountCents Int\n  purchasedAt DateTime @default(now())\n\n  @@unique([tenantId, userId, moduleId])\n  @@index([tenantId, userId])\n  @@index([tenantId, moduleId])\n  @@index([tenantId, purchasedAt])\n}\n\nmodel Payout {\n  id              String    @id @default(cuid())\n  tenantId        String\n  stripeAccountId String\n  stripePayoutId  String    @unique\n  amountCents     Int\n  currency        String    @default(\"usd\")\n  status          String    @default(\"PENDING\")\n  arrivalDate     DateTime?\n  description     String?\n  metadata        String? // JSON string\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n\n  @@index([tenantId, stripeAccountId])\n  @@index([tenantId, status])\n  @@index([stripePayoutId])\n}\n\n// =============================================================================\n// Subscription & Payment Management\n// =============================================================================\n\nenum SubscriptionTier {\n  FREE\n  STARTER\n  PROFESSIONAL\n  ENTERPRISE\n}\n\nenum SubscriptionStatus {\n  ACTIVE\n  PAST_DUE\n  CANCELED\n  INCOMPLETE\n  INCOMPLETE_EXPIRED\n  TRIALING\n  UNPAID\n}\n\nenum BillingInterval {\n  MONTHLY\n  QUARTERLY\n  ANNUAL\n}\n\nmodel StripeCustomer {\n  id               String   @id @default(cuid())\n  tenantId         String   @unique\n  stripeCustomerId String   @unique\n  email            String\n  name             String?\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  subscriptions  Subscription[]\n  paymentMethods PaymentMethod[]\n  invoices       Invoice[]\n\n  @@index([tenantId])\n}\n\nmodel Subscription {\n  id                   String             @id @default(cuid())\n  tenantId             String\n  customer             StripeCustomer     @relation(fields: [stripeCustomerId], references: [stripeCustomerId], onDelete: Cascade)\n  stripeCustomerId     String\n  stripeSubscriptionId String             @unique\n  stripePriceId        String\n  tier                 SubscriptionTier\n  status               SubscriptionStatus\n  billingInterval      BillingInterval\n  currentPeriodStart   DateTime\n  currentPeriodEnd     DateTime\n  cancelAtPeriodEnd    Boolean            @default(false)\n  canceledAt           DateTime?\n  trialStart           DateTime?\n  trialEnd             DateTime?\n  createdAt            DateTime           @default(now())\n  updatedAt            DateTime           @updatedAt\n\n  invoices       Invoice[]\n  usageSnapshots UsageSnapshot[]\n\n  @@index([tenantId])\n  @@index([stripeCustomerId])\n  @@index([status])\n}\n\nmodel PaymentMethod {\n  id                    String         @id @default(cuid())\n  tenantId              String\n  customer              StripeCustomer @relation(fields: [stripeCustomerId], references: [stripeCustomerId], onDelete: Cascade)\n  stripeCustomerId      String\n  stripePaymentMethodId String         @unique\n  type                  String\n  isDefault             Boolean        @default(false)\n  lastFour              String?\n  brand                 String?\n  expMonth              Int?\n  expYear               Int?\n  createdAt             DateTime       @default(now())\n\n  transactions Transaction[]\n\n  @@index([tenantId])\n  @@index([stripeCustomerId])\n}\n\nmodel Invoice {\n  id               String         @id @default(cuid())\n  tenantId         String\n  customer         StripeCustomer @relation(fields: [stripeCustomerId], references: [stripeCustomerId], onDelete: Cascade)\n  stripeCustomerId String\n  subscription     Subscription?  @relation(fields: [subscriptionId], references: [id])\n  subscriptionId   String?\n  stripeInvoiceId  String         @unique\n  number           String\n  status           String\n  currency         String\n  subtotalCents    Int\n  taxCents         Int\n  totalCents       Int\n  amountPaidCents  Int\n  amountDueCents   Int\n  dueDate          DateTime\n  paidAt           DateTime?\n  hostedInvoiceUrl String?\n  invoicePdfUrl    String?\n  createdAt        DateTime       @default(now())\n\n  transactions Transaction[]\n\n  @@index([tenantId])\n  @@index([stripeCustomerId])\n  @@index([subscriptionId])\n  @@index([status])\n}\n\nmodel Transaction {\n  id                    String         @id @default(cuid())\n  tenantId              String\n  invoice               Invoice?       @relation(fields: [invoiceId], references: [id])\n  invoiceId             String?\n  paymentMethod         PaymentMethod? @relation(fields: [paymentMethodId], references: [id])\n  paymentMethodId       String?\n  stripePaymentIntentId String?\n  stripeChargeId        String?\n  type                  String\n  status                String\n  amountCents           Int\n  currency              String\n  failureReason         String?\n  receiptUrl            String?\n  createdAt             DateTime       @default(now())\n  processedAt           DateTime?\n\n  @@index([tenantId])\n  @@index([invoiceId])\n  @@index([status])\n}\n\nmodel WebhookEvent {\n  id            String    @id @default(cuid())\n  stripeEventId String    @unique\n  type          String\n  data          Json\n  processed     Boolean   @default(false)\n  processedAt   DateTime?\n  error         String?\n  createdAt     DateTime  @default(now())\n\n  @@index([processed])\n  @@index([type])\n}\n\nmodel UsageSnapshot {\n  id             String       @id @default(cuid())\n  tenantId       String\n  subscription   Subscription @relation(fields: [subscriptionId], references: [id], onDelete: Cascade)\n  subscriptionId String\n  periodStart    DateTime\n  periodEnd      DateTime\n  users          Int          @default(0)\n  modules        Int          @default(0)\n  storageGB      Float        @default(0)\n  classrooms     Int          @default(0)\n  vrSessions     Int          @default(0)\n  capturedAt     DateTime     @default(now())\n\n  @@index([tenantId])\n  @@index([subscriptionId])\n  @@index([periodStart, periodEnd])\n}\n\n// =============================================================================\n// LTI Integration\n// =============================================================================\n\nmodel LTIPlatform {\n  id           String   @id @default(cuid())\n  tenantId     String\n  platformName String\n  issuer       String\n  clientId     String\n  jwksUrl      String\n  authUrl      String\n  tokenUrl     String\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@unique([tenantId, issuer])\n  @@index([tenantId])\n}\n\n// =============================================================================\n// Social Learning - Study Groups (Block 4 - Days 41-45)\n// =============================================================================\n\nenum StudyGroupVisibility {\n  PUBLIC\n  PRIVATE\n  CLASSROOM_ONLY\n}\n\nenum StudyGroupStatus {\n  ACTIVE\n  ARCHIVED\n  SUSPENDED\n}\n\nenum StudyGroupRole {\n  OWNER\n  ADMIN\n  MODERATOR\n  MEMBER\n}\n\nmodel StudyGroup {\n  id              String               @id @default(cuid())\n  tenantId        String\n  name            String\n  description     String\n  coverImageUrl   String?\n  createdBy       String\n  visibility      StudyGroupVisibility @default(PUBLIC)\n  maxMembers      Int                  @default(50)\n  requireApproval Boolean              @default(false)\n  allowGuestView  Boolean              @default(false)\n  subjects        String // JSON array\n  modules         String? // JSON array of module IDs\n  memberCount     Int                  @default(1)\n  status          StudyGroupStatus     @default(ACTIVE)\n  lastActivityAt  DateTime             @default(now())\n  archivedAt      DateTime?\n  createdAt       DateTime             @default(now())\n  updatedAt       DateTime             @updatedAt\n\n  members      StudyGroupMember[]\n  joinRequests StudyGroupJoinRequest[]\n  invites      StudyGroupInvite[]\n  sessions     StudySession[]\n  chatRoom     ChatRoom?\n  forum        Forum?\n  sharedNotes  SharedNote[]\n\n  @@index([tenantId, status])\n  @@index([tenantId, visibility])\n  @@index([tenantId, createdBy])\n}\n\nmodel StudyGroupMember {\n  id                   String         @id @default(cuid())\n  group                StudyGroup     @relation(fields: [groupId], references: [id], onDelete: Cascade)\n  groupId              String\n  userId               String\n  role                 StudyGroupRole @default(MEMBER)\n  invitedBy            String?\n  messagesCount        Int            @default(0)\n  notificationsEnabled Boolean        @default(true)\n  mutedUntil           DateTime?\n  lastActiveAt         DateTime       @default(now())\n  joinedAt             DateTime       @default(now())\n\n  @@unique([groupId, userId])\n  @@index([userId])\n}\n\nenum JoinRequestStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nmodel StudyGroupJoinRequest {\n  id              String            @id @default(cuid())\n  group           StudyGroup        @relation(fields: [groupId], references: [id], onDelete: Cascade)\n  groupId         String\n  userId          String\n  message         String?\n  status          JoinRequestStatus @default(PENDING)\n  reviewedBy      String?\n  rejectionReason String?\n  reviewedAt      DateTime?\n  createdAt       DateTime          @default(now())\n\n  @@unique([groupId, userId, status])\n  @@index([groupId, status])\n}\n\nenum InviteStatus {\n  PENDING\n  ACCEPTED\n  DECLINED\n  EXPIRED\n}\n\nmodel StudyGroupInvite {\n  id           String       @id @default(cuid())\n  group        StudyGroup   @relation(fields: [groupId], references: [id], onDelete: Cascade)\n  groupId      String\n  invitedEmail String\n  invitedBy    String\n  status       InviteStatus @default(PENDING)\n  acceptedAt   DateTime?\n  expiresAt    DateTime\n  createdAt    DateTime     @default(now())\n\n  @@unique([groupId, invitedEmail])\n  @@index([invitedEmail, status])\n}\n\n// =============================================================================\n// Social Learning - Study Sessions\n// =============================================================================\n\nenum StudySessionType {\n  DISCUSSION\n  REVIEW\n  QUIZ_PRACTICE\n  VIDEO_CALL\n  COLLABORATIVE\n}\n\nenum StudySessionStatus {\n  SCHEDULED\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n}\n\nmodel StudySession {\n  id              String             @id @default(cuid())\n  group           StudyGroup         @relation(fields: [groupId], references: [id], onDelete: Cascade)\n  groupId         String\n  title           String\n  description     String?\n  createdBy       String\n  scheduledAt     DateTime\n  duration        Int // minutes\n  timezone        String             @default(\"UTC\")\n  type            StudySessionType   @default(DISCUSSION)\n  meetingUrl      String?\n  maxParticipants Int?\n  rsvpDeadline    DateTime?\n  moduleId        String?\n  lessonIds       String? // JSON array\n  agenda          String?\n  attachments     String? // JSON array\n  status          StudySessionStatus @default(SCHEDULED)\n  startedAt       DateTime?\n  endedAt         DateTime?\n  notes           String?\n  recordingUrl    String?\n  createdAt       DateTime           @default(now())\n  updatedAt       DateTime           @updatedAt\n\n  rsvps SessionRsvp[]\n\n  @@index([groupId, scheduledAt])\n  @@index([groupId, status])\n}\n\nenum RsvpStatus {\n  ATTENDING\n  MAYBE\n  NOT_ATTENDING\n}\n\nmodel SessionRsvp {\n  id        String       @id @default(cuid())\n  session   StudySession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  sessionId String\n  userId    String\n  status    RsvpStatus\n  note      String?\n  createdAt DateTime     @default(now())\n\n  @@unique([sessionId, userId])\n}\n\n// =============================================================================\n// Social Learning - Discussion Forums\n// =============================================================================\n\nenum ForumScope {\n  GLOBAL\n  STUDY_GROUP\n  CLASSROOM\n  MODULE\n}\n\nenum ForumStatus {\n  ACTIVE\n  ARCHIVED\n  LOCKED\n}\n\nmodel Forum {\n  id                  String      @id @default(cuid())\n  tenantId            String\n  name                String\n  description         String\n  iconUrl             String?\n  scope               ForumScope  @default(GLOBAL)\n  scopeId             String? // groupId, classroomId, or moduleId\n  allowAnonymousPosts Boolean     @default(false)\n  requireModeration   Boolean     @default(false)\n  allowAttachments    Boolean     @default(true)\n  allowPolls          Boolean     @default(true)\n  categories          String? // JSON array of ForumCategory\n  topicCount          Int         @default(0)\n  postCount           Int         @default(0)\n  lastPostAt          DateTime?\n  status              ForumStatus @default(ACTIVE)\n  studyGroup          StudyGroup? @relation(fields: [studyGroupId], references: [id])\n  studyGroupId        String?     @unique\n  createdAt           DateTime    @default(now())\n  updatedAt           DateTime    @updatedAt\n\n  topics ForumTopic[]\n\n  @@index([tenantId, scope])\n  @@index([tenantId, scopeId])\n}\n\nenum TopicStatus {\n  DRAFT\n  PENDING\n  PUBLISHED\n  HIDDEN\n  DELETED\n}\n\nmodel ForumTopic {\n  id             String      @id @default(cuid())\n  forum          Forum       @relation(fields: [forumId], references: [id], onDelete: Cascade)\n  forumId        String\n  categoryId     String?\n  title          String\n  slug           String\n  authorId       String\n  authorName     String\n  content        String\n  contentFormat  String      @default(\"markdown\")\n  attachments    String? // JSON array\n  viewCount      Int         @default(0)\n  replyCount     Int         @default(0)\n  likeCount      Int         @default(0)\n  isPinned       Boolean     @default(false)\n  isLocked       Boolean     @default(false)\n  isAnswered     Boolean     @default(false)\n  answerId       String?\n  status         TopicStatus @default(PUBLISHED)\n  moderatedBy    String?\n  moderatedAt    DateTime?\n  moderationNote String?\n  lastReplyAt    DateTime?\n  lastReplyBy    String?\n  createdAt      DateTime    @default(now())\n  updatedAt      DateTime    @updatedAt\n\n  posts ForumPost[]\n\n  @@unique([forumId, slug])\n  @@index([forumId, isPinned])\n  @@index([forumId, status])\n  @@index([authorId])\n}\n\nmodel ForumPost {\n  id               String      @id @default(cuid())\n  topic            ForumTopic  @relation(fields: [topicId], references: [id], onDelete: Cascade)\n  topicId          String\n  authorId         String\n  authorName       String\n  isAnonymous      Boolean     @default(false)\n  content          String\n  contentFormat    String      @default(\"markdown\")\n  attachments      String? // JSON array\n  parentId         String?\n  depth            Int         @default(0)\n  likeCount        Int         @default(0)\n  isAcceptedAnswer Boolean     @default(false)\n  status           TopicStatus @default(PUBLISHED)\n  moderatedBy      String?\n  moderatedAt      DateTime?\n  isEdited         Boolean     @default(false)\n  editedAt         DateTime?\n  editHistory      String? // JSON array of PostEdit\n  createdAt        DateTime    @default(now())\n  updatedAt        DateTime    @updatedAt\n\n  reactions PostReaction[]\n\n  @@index([topicId, createdAt])\n  @@index([topicId, parentId])\n  @@index([authorId])\n}\n\nenum ReactionType {\n  LIKE\n  HELPFUL\n  INSIGHTFUL\n  QUESTION\n  CELEBRATE\n}\n\nmodel PostReaction {\n  id        String       @id @default(cuid())\n  post      ForumPost    @relation(fields: [postId], references: [id], onDelete: Cascade)\n  postId    String\n  userId    String\n  type      ReactionType\n  createdAt DateTime     @default(now())\n\n  @@unique([postId, userId, type])\n  @@index([postId])\n}\n\n// =============================================================================\n// Social Learning - Peer Tutoring\n// =============================================================================\n\nenum TutorStatus {\n  ACTIVE\n  PAUSED\n  INACTIVE\n}\n\nmodel TutorProfile {\n  id                   String      @id @default(cuid())\n  tenantId             String\n  userId               String\n  displayName          String\n  bio                  String\n  avatarUrl            String?\n  subjects             String // JSON array\n  modules              String? // JSON array of module IDs\n  qualifications       String? // JSON array\n  isAvailable          Boolean     @default(true)\n  availabilitySchedule String? // JSON array of AvailabilitySlot\n  timezone             String      @default(\"UTC\")\n  responseTime         String      @default(\"Usually within 2 hours\")\n  sessionTypes         String // JSON array of TutoringSessionType\n  maxSessionsPerWeek   Int         @default(5)\n  pricePerHour         Int? // In cents, if paid tutoring\n  rating               Float       @default(0)\n  reviewCount          Int         @default(0)\n  sessionsCompleted    Int         @default(0)\n  totalHelpedStudents  Int         @default(0)\n  status               TutorStatus @default(ACTIVE)\n  verifiedAt           DateTime?\n  verifiedBy           String?\n  createdAt            DateTime    @default(now())\n  updatedAt            DateTime    @updatedAt\n\n  requests TutoringRequest[] @relation(\"TutorRequests\")\n  sessions TutoringSession[] @relation(\"TutorSessions\")\n  reviews  TutoringReview[]  @relation(\"TutorReviews\")\n\n  @@unique([tenantId, userId])\n  @@index([tenantId, status])\n  @@index([tenantId, isAvailable])\n}\n\nenum TutoringRequestStatus {\n  OPEN\n  MATCHED\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n  EXPIRED\n}\n\nmodel TutoringRequest {\n  id                 String                @id @default(cuid())\n  tenantId           String\n  studentId          String\n  tutor              TutorProfile?         @relation(\"TutorRequests\", fields: [tutorId], references: [id])\n  tutorId            String?\n  subject            String\n  moduleId           String?\n  lessonId           String?\n  title              String\n  description        String\n  attachments        String? // JSON array\n  preferredTypes     String // JSON array of TutoringSessionType\n  preferredTime      DateTime?\n  estimatedDuration  Int                   @default(60)\n  urgency            String                @default(\"medium\")\n  status             TutoringRequestStatus @default(OPEN)\n  acceptedAt         DateTime?\n  completedAt        DateTime?\n  cancelledAt        DateTime?\n  cancellationReason String?\n  createdAt          DateTime              @default(now())\n  updatedAt          DateTime              @updatedAt\n\n  sessions TutoringSession[]\n\n  @@index([tenantId, status])\n  @@index([tenantId, studentId])\n  @@index([tenantId, tutorId])\n}\n\nenum TutoringSessionStatus {\n  SCHEDULED\n  IN_PROGRESS\n  COMPLETED\n  NO_SHOW\n  CANCELLED\n}\n\nmodel TutoringSession {\n  id              String                @id @default(cuid())\n  tenantId        String\n  request         TutoringRequest       @relation(fields: [requestId], references: [id])\n  requestId       String\n  studentId       String\n  tutor           TutorProfile          @relation(\"TutorSessions\", fields: [tutorId], references: [id])\n  tutorId         String\n  type            String // TutoringSessionType\n  scheduledAt     DateTime\n  duration        Int // minutes\n  meetingUrl      String?\n  moduleId        String?\n  lessonId        String?\n  notes           String?\n  sharedResources String? // JSON array\n  status          TutoringSessionStatus @default(SCHEDULED)\n  startedAt       DateTime?\n  endedAt         DateTime?\n  actualDuration  Int?\n  recordingUrl    String?\n  transcriptUrl   String?\n  createdAt       DateTime              @default(now())\n  updatedAt       DateTime              @updatedAt\n\n  reviews  TutoringReview[]\n  chatRoom ChatRoom?\n\n  @@index([tenantId, status])\n  @@index([tenantId, studentId])\n  @@index([tenantId, tutorId])\n  @@index([scheduledAt])\n}\n\nmodel TutoringReview {\n  id            String          @id @default(cuid())\n  session       TutoringSession @relation(fields: [sessionId], references: [id])\n  sessionId     String\n  tutor         TutorProfile    @relation(\"TutorReviews\", fields: [tutorId], references: [id])\n  tutorId       String\n  reviewerId    String\n  rating        Int // 1-5\n  helpfulness   Int // 1-5\n  communication Int // 1-5\n  knowledge     Int // 1-5\n  comment       String?\n  privateNote   String?\n  response      String?\n  respondedAt   DateTime?\n  isVisible     Boolean         @default(true)\n  moderatedBy   String?\n  moderatedAt   DateTime?\n  createdAt     DateTime        @default(now())\n  updatedAt     DateTime        @updatedAt\n\n  @@unique([sessionId, reviewerId])\n  @@index([tutorId, isVisible])\n}\n\n// =============================================================================\n// Social Learning - Real-time Chat\n// =============================================================================\n\nenum ChatRoomType {\n  DIRECT\n  STUDY_GROUP\n  CLASSROOM\n  TUTORING\n  SUPPORT\n}\n\nmodel ChatRoom {\n  id                String           @id @default(cuid())\n  tenantId          String\n  type              ChatRoomType\n  name              String?\n  studyGroup        StudyGroup?      @relation(fields: [studyGroupId], references: [id])\n  studyGroupId      String?          @unique\n  tutoringSession   TutoringSession? @relation(fields: [tutoringSessionId], references: [id])\n  tutoringSessionId String?          @unique\n  participants      String // JSON array of user IDs\n  maxParticipants   Int?\n  isEncrypted       Boolean          @default(false)\n  retentionDays     Int              @default(90)\n  messageCount      Int              @default(0)\n  lastMessageAt     DateTime?\n  createdAt         DateTime         @default(now())\n  updatedAt         DateTime         @updatedAt\n\n  messages     ChatMessage[]\n  readReceipts ChatReadReceipt[]\n\n  @@index([tenantId, type])\n  @@index([tenantId, studyGroupId])\n}\n\nenum ChatMessageType {\n  TEXT\n  IMAGE\n  FILE\n  CODE\n  MATH\n  QUIZ_SHARE\n  SYSTEM\n}\n\nmodel ChatMessage {\n  id          String          @id @default(cuid())\n  room        ChatRoom        @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId      String\n  senderId    String\n  senderName  String\n  type        ChatMessageType @default(TEXT)\n  content     String\n  metadata    String? // JSON object\n  attachments String? // JSON array\n  replyToId   String?\n  reactions   String? // JSON object: emoji -> userIds[]\n  status      String          @default(\"sent\")\n  editedAt    DateTime?\n  deletedAt   DateTime?\n  createdAt   DateTime        @default(now())\n\n  @@index([roomId, createdAt])\n  @@index([roomId, senderId])\n}\n\nmodel ChatReadReceipt {\n  id                String   @id @default(cuid())\n  room              ChatRoom @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId            String\n  userId            String\n  lastReadMessageId String\n  lastReadAt        DateTime @default(now())\n\n  @@unique([roomId, userId])\n}\n\n// =============================================================================\n// Social Learning - Collaborative Features\n// =============================================================================\n\nmodel SharedNote {\n  id            String      @id @default(cuid())\n  tenantId      String\n  createdBy     String\n  studyGroup    StudyGroup? @relation(fields: [studyGroupId], references: [id])\n  studyGroupId  String?\n  title         String\n  content       String // JSON for rich text\n  version       Int         @default(1)\n  allowEditing  Boolean     @default(false)\n  allowComments Boolean     @default(true)\n  moduleId      String?\n  lessonId      String?\n  sharedWith    String? // JSON array of SharedNoteAccess\n  lastEditedBy  String?\n  createdAt     DateTime    @default(now())\n  updatedAt     DateTime    @updatedAt\n\n  comments NoteComment[]\n\n  @@index([tenantId, createdBy])\n  @@index([tenantId, studyGroupId])\n}\n\nmodel NoteComment {\n  id          String     @id @default(cuid())\n  note        SharedNote @relation(fields: [noteId], references: [id], onDelete: Cascade)\n  noteId      String\n  authorId    String\n  anchorStart Int?\n  anchorEnd   Int?\n  content     String\n  parentId    String?\n  isResolved  Boolean    @default(false)\n  resolvedBy  String?\n  resolvedAt  DateTime?\n  createdAt   DateTime   @default(now())\n  updatedAt   DateTime   @updatedAt\n\n  @@index([noteId, isResolved])\n}\n\nmodel CollaborativeWhiteboard {\n  id             String   @id @default(cuid())\n  tenantId       String\n  studyGroupId   String?\n  sessionId      String? // TutoringSession ID\n  name           String\n  canvasState    String // JSON canvas data\n  activeUsers    String? // JSON array of user IDs\n  allowAnonymous Boolean  @default(false)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  @@index([tenantId, studyGroupId])\n}\n\n// =============================================================================\n// Social Learning - Activity & Notifications\n// =============================================================================\n\nenum SocialActivityType {\n  JOINED_GROUP\n  CREATED_TOPIC\n  REPLIED_TOPIC\n  LIKED_POST\n  SCHEDULED_SESSION\n  COMPLETED_SESSION\n  SHARED_NOTE\n  EARNED_BADGE\n  HELPED_PEER\n}\n\nmodel SocialActivity {\n  id             String             @id @default(cuid())\n  tenantId       String\n  actorId        String\n  actorName      String\n  actorAvatarUrl String?\n  type           SocialActivityType\n  targetType     String // study_group, forum_topic, etc.\n  targetId       String\n  targetTitle    String\n  studyGroupId   String?\n  classroomId    String?\n  metadata       String? // JSON object\n  createdAt      DateTime           @default(now())\n\n  @@index([tenantId, createdAt])\n  @@index([tenantId, actorId])\n  @@index([tenantId, studyGroupId])\n}\n\nenum SocialNotificationType {\n  GROUP_INVITE\n  GROUP_JOIN_REQUEST\n  GROUP_MESSAGE\n  TOPIC_REPLY\n  POST_MENTION\n  POST_REACTION\n  TUTORING_REQUEST\n  SESSION_REMINDER\n  REVIEW_RECEIVED\n}\n\nmodel SocialNotification {\n  id         String                 @id @default(cuid())\n  tenantId   String\n  userId     String\n  type       SocialNotificationType\n  title      String\n  body       String\n  iconUrl    String?\n  actionUrl  String?\n  actorId    String?\n  actorName  String?\n  targetType String?\n  targetId   String?\n  isRead     Boolean                @default(false)\n  readAt     DateTime?\n  emailSent  Boolean                @default(false)\n  pushSent   Boolean                @default(false)\n  createdAt  DateTime               @default(now())\n\n  @@index([tenantId, userId, isRead])\n  @@index([tenantId, userId, createdAt])\n}\n\nmodel NotificationPreference {\n  id           String   @id @default(cuid())\n  tenantId     String\n  userId       String\n  emailEnabled Boolean  @default(true)\n  pushEnabled  Boolean  @default(true)\n  preferences  String? // JSON object: notificationType -> enabled\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@unique([tenantId, userId])\n}\n\n// ============================================\n// VR Labs Models\n// ============================================\n\nenum VRLabCategory {\n  CHEMISTRY\n  PHYSICS\n  BIOLOGY\n  ASTRONOMY\n  ENGINEERING\n  ANATOMY\n  GEOLOGY\n  HISTORY\n  ART\n  MATHEMATICS\n}\n\nenum VRLabDifficulty {\n  BEGINNER\n  INTERMEDIATE\n  ADVANCED\n  EXPERT\n}\n\nenum VRSessionStatus {\n  INITIALIZING\n  LOADING\n  ACTIVE\n  PAUSED\n  COMPLETED\n  FAILED\n}\n\nenum VRMultiplayerStatus {\n  LOBBY\n  ACTIVE\n  ENDED\n}\n\nmodel VRLab {\n  id                String          @id @default(cuid())\n  tenantId          String\n  slug              String\n  title             String\n  description       String\n  category          VRLabCategory\n  difficulty        VRLabDifficulty\n  thumbnailUrl      String\n  previewVideoUrl   String?\n  estimatedDuration Int // minutes\n  requiredDevices   String // JSON array\n  minRequirements   String // JSON object\n  completionRate    Float           @default(0)\n  averageRating     Float           @default(0)\n  totalSessions     Int             @default(0)\n  memberCount       Int             @default(0)\n  isPublished       Boolean         @default(false)\n  tags              String // JSON array\n  prerequisites     String? // JSON array of VRLabIds\n  createdBy         String\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n\n  scenes      VRScene[]\n  objectives  VRLabObjective[]\n  sessions    VRSession[]\n  multiplayer VRMultiplayerSession[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId, category])\n  @@index([tenantId, isPublished])\n  @@index([tenantId, difficulty])\n}\n\nmodel VRScene {\n  id                String  @id @default(cuid())\n  labId             String\n  name              String\n  description       String\n  order             Int\n  environmentUrl    String\n  skyboxUrl         String?\n  lightingPreset    String\n  spawnPoints       String // JSON array of positions\n  ambientSoundUrl   String?\n  narrationUrl      String?\n  estimatedDuration Int\n\n  lab           VRLab            @relation(fields: [labId], references: [id], onDelete: Cascade)\n  interactables VRInteractable[]\n\n  @@index([labId, order])\n}\n\nmodel VRInteractable {\n  id                  String  @id @default(cuid())\n  sceneId             String\n  name                String\n  type                String // equipment, chemical, specimen, tool, etc.\n  position            String // JSON {x, y, z}\n  rotation            String // JSON {x, y, z, w}\n  scale               String // JSON {x, y, z}\n  modelUrl            String\n  materialOverrides   String? // JSON array\n  allowedInteractions String // JSON array of interaction types\n  interactionRange    Float\n  behavior            String // JSON object\n  tooltip             String?\n  audioFeedbackUrl    String?\n\n  scene VRScene @relation(fields: [sceneId], references: [id], onDelete: Cascade)\n\n  @@index([sceneId])\n}\n\nmodel VRLabObjective {\n  id          String  @id @default(cuid())\n  labId       String\n  title       String\n  description String?\n  order       Int\n  type        String // interaction, observation, quiz, experiment\n  criteria    String // JSON object\n  hints       String // JSON array\n  points      Int\n  isOptional  Boolean @default(false)\n\n  lab VRLab @relation(fields: [labId], references: [id], onDelete: Cascade)\n\n  @@index([labId, order])\n}\n\nmodel VRSession {\n  id                 String          @id @default(cuid())\n  tenantId           String\n  userId             String\n  labId              String\n  status             VRSessionStatus\n  currentSceneId     String\n  deviceType         String\n  deviceInfo         String // JSON object\n  progress           String // JSON object with completedObjectives, points, etc.\n  startedAt          DateTime\n  lastActiveAt       DateTime\n  endedAt            DateTime?\n  totalDuration      Int             @default(0) // seconds\n  performanceMetrics String // JSON object\n\n  lab VRLab @relation(fields: [labId], references: [id])\n\n  @@index([tenantId, userId])\n  @@index([tenantId, labId])\n  @@index([userId, status])\n}\n\nmodel VRMultiplayerSession {\n  id                  String              @id @default(cuid())\n  tenantId            String\n  labId               String\n  hostUserId          String\n  maxParticipants     Int\n  voiceChatEnabled    Boolean             @default(true)\n  spatialAudioEnabled Boolean             @default(true)\n  participants        String // JSON array of VRParticipant\n  status              VRMultiplayerStatus @default(LOBBY)\n  createdAt           DateTime            @default(now())\n\n  lab VRLab @relation(fields: [labId], references: [id])\n\n  @@index([tenantId, status])\n  @@index([labId, status])\n}\n\nmodel VRAsset {\n  id           String   @id @default(cuid())\n  tenantId     String\n  name         String\n  type         String // model, texture, audio, video, skybox, animation, script\n  url          String\n  size         Int // bytes\n  format       String\n  s3Key        String\n  thumbnailUrl String?\n  tags         String // JSON array\n  isPublic     Boolean  @default(false)\n  status       String   @default(\"ready\") // pending, ready, error\n  createdBy    String\n  createdAt    DateTime @default(now())\n\n  @@index([tenantId, type])\n  @@index([tenantId, isPublic])\n}\n\nmodel VRAnalyticsEvent {\n  id        String   @id @default(cuid())\n  tenantId  String\n  userId    String\n  eventType String\n  labId     String?\n  sessionId String?\n  metadata  String // JSON object\n  timestamp DateTime @default(now())\n\n  @@index([tenantId, eventType])\n  @@index([tenantId, labId])\n  @@index([tenantId, timestamp])\n}\n\n// =============================================================================\n// Curriculum & Domain Content Models\n// =============================================================================\n\nenum CurriculumLevel {\n  FOUNDATIONAL\n  INTERMEDIATE\n  ADVANCED\n  RESEARCH\n}\n\nenum SimulationDomain {\n  CS_DISCRETE\n  PHYSICS\n  CHEMISTRY\n  BIOLOGY\n  MEDICINE\n  ECONOMICS\n  ENGINEERING\n  MATHEMATICS\n}\n\nenum AnimationDomain {\n  MATH\n  SCIENCE\n  TECH\n  ENGINEERING\n  MEDICINE\n  HEALTH\n  BUSINESS\n  MANAGEMENT\n  ECONOMICS\n  COMPUTER_SCIENCE\n  INTERDISCIPLINARY\n}\n\nenum ContentStatus {\n  PUBLISHED\n  DRAFT\n}\n\nmodel DomainConcept {\n  id                     String           @id @default(cuid())\n  tenantId               String\n  externalId             String // Original ID from JSON (e.g., \"phy_F_1\")\n  name                   String\n  description            String\n  domain                 SimulationDomain\n  level                  CurriculumLevel\n  keywords               String // JSON array\n  audienceTags           String // JSON array\n  simulationMetadata     Json\n  learningObjectMetadata Json\n  pedagogicalMetadata    Json\n  crossDomainLinks       Json // Array of cross-domain references\n  status                 ContentStatus    @default(DRAFT)\n  createdAt              DateTime         @default(now())\n  updatedAt              DateTime         @updatedAt\n\n  // Relations\n  prerequisites       ConceptPrerequisite[] @relation(\"ConceptDependents\")\n  requiredBy          ConceptPrerequisite[] @relation(\"ConceptPrerequisites\")\n  moduleMapping       ConceptModuleMapping?\n  simulationTemplates SimulationTemplate[]\n\n  @@unique([tenantId, externalId])\n  @@index([tenantId, domain])\n  @@index([tenantId, level])\n  @@index([tenantId, status])\n}\n\nmodel ConceptPrerequisite {\n  concept        DomainConcept @relation(\"ConceptDependents\", fields: [conceptId], references: [id], onDelete: Cascade)\n  conceptId      String\n  prerequisite   DomainConcept @relation(\"ConceptPrerequisites\", fields: [prerequisiteId], references: [id], onDelete: Cascade)\n  prerequisiteId String\n\n  @@id([conceptId, prerequisiteId])\n}\n\nmodel ConceptModuleMapping {\n  id                    String        @id @default(cuid())\n  concept               DomainConcept @relation(fields: [conceptId], references: [id], onDelete: Cascade)\n  conceptId             String        @unique\n  moduleId              String\n  simulationManifestIds String // JSON array of manifest IDs\n  createdAt             DateTime      @default(now())\n\n  @@index([moduleId])\n}\n\nenum SimulationTemplateDifficulty {\n  BEGINNER\n  INTERMEDIATE\n  ADVANCED\n  EXPERT\n}\n\nenum SimulationTemplateLicense {\n  FREE\n  CC_BY\n  CC_BY_SA\n  CC_BY_NC\n  PROPRIETARY\n}\n\nenum SimulationTemplateStatus {\n  DRAFT\n  PUBLISHED\n  ARCHIVED\n}\n\nmodel SimulationManifest {\n  id          String           @id // Stable manifest ID generated from concept\n  tenantId    String\n  domain      SimulationDomain\n  version     String\n  title       String\n  description String?\n  module      Module?          @relation(fields: [moduleId], references: [id], onDelete: SetNull)\n  moduleId    String?\n  manifest    Json // Full SimulationManifest payload\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  templates        SimulationTemplate[]\n  experiences      LearningExperience[]         @relation(\"ExperienceSimulation\")\n  versions         SimulationManifestVersion[]  @relation(\"SimulationManifestVersions\")\n  extension        SimulationManifestExtension? @relation(\"SimulationManifestExtensions\")\n  linkAudits       SimulationLinkAudit[]        @relation(\"SimulationLinkAudits\")\n  claimSimulations ClaimSimulation[]\n  artifacts        ArtifactManifest[]           @relation(\"ArtifactSimulation\")\n\n  @@index([tenantId, domain])\n  @@index([tenantId, moduleId])\n}\n\nmodel SimulationTemplate {\n  id                  String                       @id @default(cuid())\n  tenantId            String\n  slug                String\n  title               String\n  description         String\n  domain              SimulationDomain\n  difficulty          SimulationTemplateDifficulty\n  tags                String // JSON array of tags\n  thumbnailUrl        String?\n  license             SimulationTemplateLicense    @default(FREE)\n  isPremium           Boolean                      @default(false)\n  isVerified          Boolean                      @default(false)\n  version             String // Semantic version, e.g. \"1.0.0\"\n  authorId            String\n  authorName          String?\n  authorAvatarUrl     String?\n  organization        String?\n  statsViews          Int                          @default(0)\n  statsUses           Int                          @default(0)\n  statsFavorites      Int                          @default(0)\n  statsRating         Float                        @default(0)\n  statsRatingCount    Int                          @default(0)\n  statsCompletionRate Float                        @default(0)\n  statsAvgTimeMinutes Int                          @default(0)\n  status              SimulationTemplateStatus     @default(DRAFT)\n  publishedAt         DateTime?\n  createdAt           DateTime                     @default(now())\n  updatedAt           DateTime                     @updatedAt\n\n  // Relations\n  concept    DomainConcept?      @relation(fields: [conceptId], references: [id], onDelete: SetNull)\n  conceptId  String?\n  module     Module?             @relation(fields: [moduleId], references: [id], onDelete: SetNull)\n  moduleId   String?\n  manifest   SimulationManifest? @relation(fields: [manifestId], references: [id], onDelete: SetNull)\n  manifestId String?\n\n  @@unique([tenantId, slug])\n  @@index([tenantId, domain])\n  @@index([tenantId, difficulty])\n  @@index([tenantId, isPremium])\n  @@index([tenantId, isVerified])\n  @@index([tenantId, status])\n}\n\nmodel Curriculum {\n  id          String           @id @default(cuid())\n  tenantId    String\n  domain      SimulationDomain\n  title       String\n  description String?\n  version     String           @default(\"1.0.0\")\n  isPublished Boolean          @default(false)\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  @@unique([tenantId, domain])\n  @@index([tenantId, isPublished])\n}\n\n// =============================================================================\n// Admin & Tenant Management (Block 4 - Day 38)\n// =============================================================================\n\nmodel Tenant {\n  id               String           @id @default(cuid())\n  name             String\n  subdomain        String           @unique\n  adminEmail       String?\n  subscriptionTier SubscriptionTier @default(FREE)\n  createdAt        DateTime         @default(now())\n  updatedAt        DateTime         @updatedAt\n\n  settings           TenantSettings?\n  users              User[]\n  identityProviders  IdentityProvider[]\n  tenantCapabilities TenantCapability[]\n  tenantPlugins      TenantPlugin[]\n\n  @@index([subdomain])\n  @@map(\"tenants\")\n}\n\nmodel TenantSettings {\n  id                       String   @id @default(cuid())\n  tenant                   Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  tenantId                 String   @unique\n  allowPublicRegistration  Boolean  @default(false)\n  requireEmailVerification Boolean  @default(true)\n  defaultUserRole          String   @default(\"student\")\n  maxUsersPerClassroom     Int      @default(50)\n  enabledFeatures          String   @default(\"[]\") // JSON array\n  enabledDomainPacks       String   @default(\"[]\") // JSON array\n  simulationQuotas         String   @default(\"{}\") // JSON object\n  createdAt                DateTime @default(now())\n  updatedAt                DateTime @updatedAt\n}\n\nmodel User {\n  id             String    @id @default(cuid())\n  tenant         Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  tenantId       String\n  email          String\n  emailEncrypted String? // Encrypted PII: email\n  displayName    String\n  role           String    @default(\"student\")\n  passwordHash   String? // Scrypt-based password hash for local auth\n  lastLoginAt    DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  ssoLinks       SsoUserLink[]\n  learnerProfile LearnerProfile?\n  consents       UserConsent[]\n  userRoles      UserRole[]\n\n  @@unique([tenantId, email])\n  @@index([tenantId, role])\n}\n\nmodel UserConsent {\n  id        String    @id @default(cuid())\n  tenantId  String\n  userId    String\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  category  String // essential, analytics, ai_processing, third_party_sharing, marketing\n  granted   Boolean   @default(true)\n  grantedAt DateTime  @default(now())\n  revokedAt DateTime?\n  version   Int       @default(1)\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@unique([tenantId, userId, category])\n  @@index([tenantId, userId])\n  @@index([tenantId, userId, granted])\n}\n\n// =============================================================================\n// RBAC Models\n// =============================================================================\n\nmodel Role {\n  id          String   @id @default(cuid())\n  tenantId    String\n  name        String // e.g., \"admin\", \"teacher\", \"student\"\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  userRoles       UserRole[]\n  rolePermissions RolePermission[]\n\n  @@unique([tenantId, name])\n  @@index([tenantId])\n}\n\nmodel Permission {\n  id          String   @id @default(cuid())\n  resource    String // e.g., \"content\", \"users\", \"settings\"\n  action      String // e.g., \"read\", \"write\", \"delete\"\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  rolePermissions RolePermission[]\n\n  @@unique([resource, action])\n  @@index([resource])\n}\n\nmodel UserRole {\n  id         String   @id @default(cuid())\n  tenantId   String\n  userId     String\n  user       User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  roleId     String\n  role       Role     @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  assignedAt DateTime @default(now())\n\n  @@unique([tenantId, userId, roleId])\n  @@index([tenantId, userId])\n  @@index([tenantId, roleId])\n}\n\nmodel RolePermission {\n  id           String     @id @default(cuid())\n  roleId       String\n  role         Role       @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  permissionId String\n  permission   Permission @relation(fields: [permissionId], references: [id], onDelete: Cascade)\n  assignedAt   DateTime   @default(now())\n\n  @@unique([roleId, permissionId])\n  @@index([roleId])\n  @@index([permissionId])\n}\n\n// =============================================================================\n// Capability Registry Models\n// =============================================================================\n\nmodel Capability {\n  id                    String   @id @default(cuid())\n  name                  String // e.g., \"ai_tutor\", \"simulations\", \"vr_experiences\"\n  category              String // e.g., \"ai\", \"content\", \"infrastructure\"\n  description           String?\n  enabled               Boolean  @default(true)\n  requiresSubscription  Boolean  @default(false)\n  requiresWorkerHealthy Boolean  @default(false)\n  createdAt             DateTime @default(now())\n  updatedAt             DateTime @updatedAt\n\n  tenantCapabilities TenantCapability[]\n\n  @@unique([name])\n  @@index([category])\n  @@index([enabled])\n}\n\nmodel TenantCapability {\n  id           String     @id @default(cuid())\n  tenantId     String\n  tenant       Tenant     @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  capabilityId String\n  capability   Capability @relation(fields: [capabilityId], references: [id], onDelete: Cascade)\n  enabled      Boolean    @default(true)\n  config       String? // JSON config for capability overrides\n  enabledAt    DateTime?  @default(now())\n  disabledAt   DateTime?\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  @@index([tenantId, capabilityId])\n  @@index([capabilityId])\n}\n\n// =============================================================================\n// ABAC (Attribute-Based Access Control) Models\n// =============================================================================\n\nmodel ABACPolicy {\n  id            String   @id @default(cuid())\n  tenantId      String\n  name          String\n  description   String?\n  enabled       Boolean  @default(true)\n  effect        String   @default(\"allow\") // \"allow\" or \"deny\"\n  priority      Int      @default(0) // Higher priority policies evaluated first\n  conditions    String // JSON string of policy conditions\n  actions       String[] // Array of actions this policy applies to\n  resourceTypes String[] // Array of resource types this policy applies to\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  @@unique([tenantId, name])\n  @@index([tenantId, enabled])\n  @@index([priority])\n}\n\nmodel ABACAttribute {\n  id             String   @id @default(cuid())\n  tenantId       String\n  entityType     String // \"user\", \"resource\", \"environment\"\n  entityId       String\n  attributeName  String\n  attributeValue String\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  @@unique([tenantId, entityType, entityId, attributeName])\n  @@index([tenantId, entityType])\n  @@index([entityType, entityId])\n}\n\n// =============================================================================\n// Audit Log Models\n// =============================================================================\n\nmodel AIAuditLog {\n  id              String   @id @default(cuid())\n  tenantId        String\n  userId          String\n  modelId         String\n  modelName       String?\n  modelVersion    String?\n  endpoint        String // e.g., \"tutor/query\", \"generate-questions\"\n  requestPayload  String? // JSON string of request (may be truncated)\n  responsePayload String? // JSON string of response (may be truncated)\n  policyDecision  String? // e.g., \"allowed\", \"blocked\", \"rate_limited\"\n  latencyMs       Int?\n  success         Boolean  @default(true)\n  errorMessage    String?\n  ipAddress       String?\n  userAgent       String?\n  createdAt       DateTime @default(now())\n\n  @@index([tenantId, createdAt])\n  @@index([tenantId, userId, createdAt])\n  @@index([userId, createdAt])\n  @@index([modelId, createdAt])\n  @@index([endpoint, createdAt])\n  @@index([createdAt])\n}\n\n// =============================================================================\n// Content Evaluation Models\n// =============================================================================\n\nmodel ContentEvaluation {\n  id                String   @id @default(cuid())\n  tenantId          String\n  moduleId          String\n  contentId         String?\n  claimId           String\n  text              String\n  isCorrect         Boolean\n  confidence        Float\n  matchedSourceId   String?\n  matchedSourceType String? // \"curriculum\" or \"citation\"\n  issues            String[] // JSON array of issue strings\n  createdAt         DateTime @default(now())\n\n  @@index([tenantId, moduleId])\n  @@index([contentId])\n  @@index([isCorrect])\n}\n\n// =============================================================================\n// Golden Dataset Models\n// =============================================================================\n\nmodel GoldenDataset {\n  id             String   @id @default(cuid())\n  moduleId       String\n  inputType      String // \"question\", \"concept\", \"simulation\"\n  input          String\n  expectedOutput String\n  qualityMetrics String // JSON: { clarity, accuracy, completeness }\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  regressionTests RegressionTestResult[]\n\n  @@unique([moduleId, inputType, input])\n  @@index([moduleId])\n  @@index([inputType])\n}\n\nmodel RegressionTestResult {\n  id                 String   @id @default(cuid())\n  entryId            String\n  goldenDatasetId    String\n  moduleId           String\n  input              String\n  actualOutput       String\n  expectedOutput     String\n  passed             Boolean\n  qualityDiff        String // JSON: { clarity, accuracy, completeness }\n  regressionDetected Boolean\n  timestamp          DateTime @default(now())\n\n  goldenDataset GoldenDataset @relation(fields: [goldenDatasetId], references: [id], onDelete: Cascade)\n\n  @@index([goldenDatasetId])\n  @@index([moduleId])\n  @@index([passed])\n  @@index([regressionDetected])\n  @@index([timestamp])\n}\n\n// =============================================================================\n// Content Quality Monitoring Models\n// =============================================================================\n\nmodel QualityBaseline {\n  id              String   @id @default(cuid())\n  contentId       String   @unique\n  contentType     String\n  baselineMetrics String // JSON: { clarity, accuracy, completeness, engagement }\n  establishedAt   DateTime @default(now())\n\n  @@index([contentType])\n}\n\nmodel QualityAlert {\n  id            String    @id @default(cuid())\n  contentId     String\n  contentType   String\n  metricType    String // \"clarity\", \"accuracy\", \"completeness\", \"engagement\"\n  baselineValue Float\n  currentValue  Float\n  degradation   Float\n  severity      String // \"low\", \"medium\", \"high\", \"critical\"\n  detectedAt    DateTime  @default(now())\n  resolved      Boolean   @default(false)\n  resolvedAt    DateTime?\n\n  @@index([contentId])\n  @@index([contentType])\n  @@index([severity])\n  @@index([resolved])\n  @@index([detectedAt])\n}\n\n// =============================================================================\n// Content Generation Benchmark Models\n// =============================================================================\n\nmodel ContentGenerationBenchmark {\n  id                 String   @id @default(cuid())\n  tenantId           String\n  metrics            String // JSON: BenchmarkMetrics\n  baseline           String? // JSON: BenchmarkMetrics (baseline for comparison)\n  regressionDetected Boolean\n  regressionDetails  String[] // JSON array of regression detail strings\n  isBaseline         Boolean  @default(false)\n  createdAt          DateTime @default(now())\n\n  @@index([tenantId])\n  @@index([isBaseline])\n  @@index([regressionDetected])\n  @@index([createdAt])\n}\n\n// =============================================================================\n// Compliance Evidence Models\n// =============================================================================\n\nmodel ComplianceEvidence {\n  id          String   @id @default(cuid())\n  tenantId    String\n  reportType  String // \"GDPR\", \"CCPA\", \"PEDAGOGICAL\", \"SOC2\", \"ISO27001\"\n  evidence    String // JSON: ComplianceEvidence\n  periodStart DateTime\n  periodEnd   DateTime\n  generatedAt DateTime @default(now())\n\n  @@index([tenantId])\n  @@index([reportType])\n  @@index([generatedAt])\n}\n\n// =============================================================================\n// Plugin Marketplace Models\n// =============================================================================\n\nmodel TenantPlugin {\n  id             String    @id @default(cuid())\n  tenantId       String\n  tenant         Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  pluginId       String\n  version        String\n  status         String // \"available\", \"installed\", \"active\", \"inactive\", \"error\"\n  configuration  String // JSON: plugin configuration\n  installedAt    DateTime  @default(now())\n  activatedAt    DateTime?\n  lastMigratedAt DateTime?\n\n  @@unique([tenantId, pluginId])\n  @@index([tenantId])\n  @@index([pluginId])\n  @@index([status])\n}\n\n// =============================================================================\n\nmodel LearnerProfile {\n  id                       String                      @id @default(cuid())\n  tenantId                 String\n  user                     User                        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId                   String                      @unique\n  preferredDifficulty      LearnerDifficultyPreference @default(MEDIUM)\n  preferredModality        LearnerModalityPreference   @default(MIXED)\n  preferredPacing          LearnerPacingPreference     @default(ADAPTIVE)\n  preferredSessionMinutes  Int                         @default(30)\n  notificationFrequency    String                      @default(\"daily\")\n  visualLearningScore      Float                       @default(0.25)\n  auditoryLearningScore    Float                       @default(0.25)\n  kinestheticLearningScore Float                       @default(0.25)\n  readingLearningScore     Float                       @default(0.25)\n  avgSessionMinutes        Float                       @default(30)\n  preferredTimeOfDay       String?\n  streakDays               Int                         @default(0)\n  lastActiveAt             DateTime?\n  createdAt                DateTime                    @default(now())\n  updatedAt                DateTime                    @updatedAt\n\n  masteries         LearnerMastery[]\n  knowledgeGaps     KnowledgeGap[]\n  preferenceChanges PreferenceChange[]\n  pathways          LearningPathway[]\n\n  @@index([tenantId, userId])\n  @@index([tenantId, updatedAt])\n}\n\nmodel LearnerMastery {\n  id                 String         @id @default(cuid())\n  tenantId           String\n  profile            LearnerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  profileId          String\n  conceptId          String\n  masteryProbability Float          @default(0.2)\n  confidenceScore    Float          @default(0.5)\n  attempts           Int            @default(0)\n  correctAttempts    Int            @default(0)\n  incorrectAttempts  Int            @default(0)\n  hintsUsed          Int            @default(0)\n  totalTimeSeconds   Int            @default(0)\n  lastObservedAt     DateTime       @default(now())\n  nextReviewAt       DateTime?\n  createdAt          DateTime       @default(now())\n  updatedAt          DateTime       @updatedAt\n\n  @@unique([profileId, conceptId])\n  @@index([tenantId, conceptId])\n  @@index([tenantId, masteryProbability])\n}\n\nmodel KnowledgeGap {\n  id             String                      @id @default(cuid())\n  tenantId       String\n  profile        LearnerProfile              @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  profileId      String\n  conceptId      String\n  prerequisiteId String\n  severity       KnowledgeGapSeverity        @default(MEDIUM)\n  detectedBy     KnowledgeGapDetectionMethod @default(ADAPTIVE_ANALYSIS)\n  status         String                      @default(\"OPEN\")\n  evidence       Json?\n  detectionCount Int                         @default(1)\n  lastDetectedAt DateTime                    @default(now())\n  resolvedAt     DateTime?\n  createdAt      DateTime                    @default(now())\n  updatedAt      DateTime                    @updatedAt\n\n  @@unique([profileId, conceptId, prerequisiteId, status])\n  @@index([tenantId, conceptId])\n  @@index([tenantId, severity])\n}\n\nmodel PreferenceChange {\n  id        String         @id @default(cuid())\n  tenantId  String\n  profile   LearnerProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  profileId String\n  changedBy String         @default(\"user\")\n  reason    String?\n  changes   Json\n  createdAt DateTime       @default(now())\n\n  @@index([tenantId, profileId])\n  @@index([tenantId, createdAt])\n}\n\nmodel LearningPathway {\n  id                 String               @id @default(cuid())\n  tenantId           String\n  profile            LearnerProfile       @relation(fields: [profileId], references: [id], onDelete: Cascade)\n  profileId          String\n  title              String\n  goal               String\n  status             LearnerPathwayStatus @default(ACTIVE)\n  recommendedModules Json                 @default(\"[]\")\n  currentModuleId    String?\n  progressPercent    Int                  @default(0)\n  metadata           Json?\n  createdAt          DateTime             @default(now())\n  updatedAt          DateTime             @updatedAt\n\n  @@index([tenantId, profileId])\n  @@index([tenantId, status])\n}\n\n// =============================================================================\n// SSO & Identity Federation (Block 4 - Day 36)\n// =============================================================================\n\nenum IdentityProviderType {\n  OIDC\n  SAML\n}\n\nenum SsoProviderStatus {\n  ACTIVE\n  INACTIVE\n  ERROR\n  PENDING_VERIFICATION\n}\n\nmodel IdentityProvider {\n  id                   String    @id @default(cuid())\n  tenant               Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  tenantId             String\n  type                 String    @default(\"oidc\")\n  displayName          String\n  discoveryEndpoint    String\n  clientId             String\n  clientSecret         String?\n  allowedDomains       String    @default(\"[]\") // JSON array\n  enabled              Boolean   @default(false)\n  status               String    @default(\"pending_verification\")\n  roleMapping          String? // JSON object\n  lastSuccessfulAuthAt DateTime?\n  createdAt            DateTime  @default(now())\n  updatedAt            DateTime  @updatedAt\n\n  userLinks SsoUserLink[]\n\n  @@index([tenantId, enabled])\n}\n\nmodel SsoUserLink {\n  id          String           @id @default(cuid())\n  user        User             @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId      String\n  provider    IdentityProvider @relation(fields: [providerId], references: [id], onDelete: Cascade)\n  providerId  String\n  externalId  String\n  email       String\n  displayName String?\n  avatarUrl   String?\n  lastClaims  String? // JSON object\n  linkedAt    DateTime         @default(now())\n  lastLoginAt DateTime?\n\n  @@unique([providerId, externalId])\n  @@index([userId])\n}\n\n// =============================================================================\n// Compliance & Audit (Block 4 - Day 39-40)\n// =============================================================================\n\nmodel ContentReport {\n  id                String    @id @default(cuid())\n  tenantId          String\n  userId            String\n  entityType        String // \"forumPost\", \"comment\", \"user\"\n  entityId          String\n  reason            String\n  details           String?\n  status            String    @default(\"pending\")\n  reportedAt        DateTime  @default(now())\n  resolvedAt        DateTime?\n  resolvedBy        String?\n  resolutionDetails String?\n\n  @@index([tenantId, status])\n  @@index([tenantId, userId])\n  @@index([entityType, entityId])\n}\n\nmodel Follow {\n  id          String   @id @default(cuid())\n  tenantId    String\n  followerId  String\n  followingId String\n  followedAt  DateTime @default(now())\n\n  @@unique([followerId, followingId])\n  @@index([tenantId, followerId])\n  @@index([tenantId, followingId])\n}\n\nmodel DataExportRequest {\n  id                    String    @id @default(cuid())\n  tenantId              String\n  userId                String\n  status                String    @default(\"pending\")\n  requestedAt           DateTime  @default(now())\n  estimatedCompletionAt DateTime?\n  completedAt           DateTime?\n  downloadUrl           String?\n  expiresAt             DateTime?\n\n  @@index([tenantId, status])\n  @@index([tenantId, userId])\n}\n\nmodel DataDeletionRequest {\n  id                  String    @id @default(cuid())\n  tenantId            String\n  userId              String\n  status              String    @default(\"scheduled\")\n  requestedAt         DateTime  @default(now())\n  scheduledDeletionAt DateTime\n  completedAt         DateTime?\n  retentionDays       Int       @default(30)\n\n  @@index([tenantId, status])\n  @@index([tenantId, userId])\n}\n\nmodel DeletionVerification {\n  id        String   @id @default(cuid())\n  userId    String\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n}\n\nmodel AuditLog {\n  id           String   @id @default(cuid())\n  tenantId     String\n  actorId      String\n  action       String\n  resourceType String\n  resourceId   String\n  outcome      String   @default(\"success\")\n  timestamp    DateTime @default(now())\n  ipAddress    String?\n  userAgent    String?\n  metadata     String   @default(\"{}\") // JSON object\n\n  @@index([tenantId, action])\n  @@index([tenantId, resourceType])\n  @@index([tenantId, actorId])\n  @@index([tenantId, timestamp])\n}\n\n// =============================================================================\n// Classroom Members (for admin user management)\n// =============================================================================\n\nmodel ClassroomMember {\n  id          String   @id @default(cuid())\n  classroomId String\n  userId      String\n  role        String   @default(\"student\")\n  joinedAt    DateTime @default(now())\n\n  @@unique([classroomId, userId])\n  @@index([classroomId])\n  @@index([userId])\n}\n\n// =============================================================================\n// Learning Path Enrollment (for admin pathway assignment)\n// =============================================================================\n\nmodel LearningPathEnrollment {\n  id               String    @id @default(cuid())\n  pathId           String\n  userId           String\n  tenantId         String\n  currentNodeIndex Int       @default(0)\n  startedAt        DateTime  @default(now())\n  completedAt      DateTime?\n\n  @@unique([pathId, userId])\n  @@index([tenantId, userId])\n}\n\n// =============================================================================\n// Content Authoring Models (Admin: Create domains, concepts, examples)\n// =============================================================================\n\nmodel DomainAuthor {\n  id          String           @id @default(cuid())\n  tenantId    String\n  domain      SimulationDomain\n  title       String // Display title (e.g., \"Physics 101\")\n  description String\n  author      String // Name of domain author\n  status      ContentStatus    @default(DRAFT)\n  publishedAt DateTime?\n  version     Int              @default(1)\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n\n  // Relations\n  concepts DomainAuthorConcept[]\n\n  @@unique([tenantId, domain])\n  @@index([tenantId, status])\n}\n\nmodel DomainAuthorConcept {\n  id                 String          @id @default(cuid())\n  domainId           String\n  domain             DomainAuthor    @relation(fields: [domainId], references: [id], onDelete: Cascade)\n  name               String\n  description        String\n  level              CurriculumLevel\n  orderIndex         Int             @default(0)\n  learningObjectives String // JSON array of strings\n  prerequisites      String // JSON array of concept IDs\n  competencies       String // JSON array of competency tags\n  keywords           String // JSON array of keywords\n  status             ContentStatus   @default(DRAFT)\n  version            Int             @default(1)\n  createdAt          DateTime        @default(now())\n  updatedAt          DateTime        @updatedAt\n\n  // Relations\n  simulation    SimulationDefinition?\n  visualization VisualizationDefinition?\n  examples      ContentExample[]\n\n  @@unique([domainId, name])\n  @@index([domainId, level])\n}\n\nmodel SimulationDefinition {\n  id                   String              @id @default(cuid())\n  conceptId            String              @unique\n  concept              DomainAuthorConcept @relation(fields: [conceptId], references: [id], onDelete: Cascade)\n  type                 String // e.g., \"physics-2D\", \"interactive_visualization\"\n  manifest             Json // Full simulation manifest\n  estimatedTimeMinutes Int                 @default(15)\n  interactivityLevel   String              @default(\"medium\") // low, medium, high\n  purpose              String // Pedagogical purpose\n  previewConfig        Json? // Configuration for preview\n  status               ContentStatus       @default(DRAFT)\n  version              Int                 @default(1)\n  createdAt            DateTime            @default(now())\n  updatedAt            DateTime            @updatedAt\n\n  @@index([conceptId])\n}\n\nmodel VisualizationDefinition {\n  id         String              @id @default(cuid())\n  conceptId  String              @unique\n  concept    DomainAuthorConcept @relation(fields: [conceptId], references: [id], onDelete: Cascade)\n  type       String // e.g., \"graph-2d\", \"graph-3d\", \"chart\", \"diagram\", \"molecule\"\n  config     Json // Visualization-specific configuration\n  dataSource String              @default(\"simulation\") // simulation, static, dynamic\n  status     ContentStatus       @default(DRAFT)\n  version    Int                 @default(1)\n  createdAt  DateTime            @default(now())\n  updatedAt  DateTime            @updatedAt\n\n  @@index([conceptId])\n}\n\nmodel ContentExample {\n  id                   String              @id @default(cuid())\n  conceptId            String\n  concept              DomainAuthorConcept @relation(fields: [conceptId], references: [id], onDelete: Cascade)\n  title                String\n  description          String\n  problemStatement     String // Markdown format\n  solutionContent      String // Markdown format with steps\n  keyLearningPoints    String // JSON array of key points\n  difficulty           CurriculumLevel\n  estimatedTimeMinutes Int                 @default(20)\n  orderIndex           Int                 @default(0)\n  status               ContentStatus       @default(DRAFT)\n  version              Int                 @default(1)\n  createdAt            DateTime            @default(now())\n  updatedAt            DateTime            @updatedAt\n\n  // Relations\n  visualizationSnapshots VisualizationSnapshot[]\n\n  @@unique([conceptId, title])\n  @@index([conceptId, difficulty])\n}\n\nmodel VisualizationSnapshot {\n  id              String         @id @default(cuid())\n  exampleId       String\n  example         ContentExample @relation(fields: [exampleId], references: [id], onDelete: Cascade)\n  stepNumber      Int // 1, 2, 3, etc.\n  stepDescription String // Description of what's shown at this step\n  config          Json // Visualization config at this step\n  data            Json? // Data/values rendered at this step\n  createdAt       DateTime       @default(now())\n\n  @@unique([exampleId, stepNumber])\n  @@index([exampleId])\n}\n\nenum AssetType {\n  MODEL_3D // .glb, .gltf, .obj, .fbx\n  TEXTURE // .png, .jpg, .jpeg, .webp\n  AUDIO // .mp3, .wav, .ogg\n  VIDEO // .mp4, .webm\n  DOCUMENT // .pdf, .doc, .docx\n  IMAGE // General images\n  OTHER // Misc files\n}\n\nenum AssetStatus {\n  UPLOADING\n  PROCESSING\n  READY\n  FAILED\n  ARCHIVED\n}\n\nmodel Asset {\n  id           String      @id @default(cuid())\n  tenantId     String\n  filename     String // Original filename\n  displayName  String? // Optional user-friendly name\n  fileType     AssetType\n  mimeType     String // e.g., \"model/gltf+json\", \"image/png\"\n  fileSize     Int // Size in bytes\n  url          String // CDN or S3 URL\n  thumbnailUrl String? // Generated thumbnail URL\n  metadata     Json? // File-specific metadata (dimensions, duration, etc.)\n  tags         String? // Comma-separated tags for searching\n  uploadedBy   String // User ID who uploaded\n  status       AssetStatus @default(UPLOADING)\n  createdAt    DateTime    @default(now())\n  updatedAt    DateTime    @updatedAt\n\n  @@index([tenantId, fileType])\n  @@index([tenantId, status])\n  @@index([uploadedBy])\n}\n\nmodel LearningUnit {\n  id       String @id\n  tenantId String\n  domain   String\n  level    String\n  status   String\n  version  Int    @default(1)\n\n  intent     Json\n  claims     Json\n  evidence   Json\n  tasks      Json\n  artifacts  Json\n  assessment Json\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  createdBy String\n\n  @@index([tenantId, domain])\n  @@index([tenantId, status])\n}\n\n// =============================================================================\n// Content Studio - Unified Authoring (v2.0)\n// =============================================================================\n\nenum ExperienceStatus {\n  DRAFT\n  REVIEW\n  PUBLISHED\n  ARCHIVED\n}\n\nenum ContentStudioBloomLevel {\n  REMEMBER\n  UNDERSTAND\n  APPLY\n  ANALYZE\n  EVALUATE\n  CREATE\n}\n\nenum ValidationStatus {\n  PASS\n  WARN\n  FAIL\n}\n\nenum AIOperation {\n  GENERATE_EXPERIENCE\n  VALIDATE\n  IMPROVE\n  EXPAND_GRADE\n  GENERATE_SIMULATION\n  GENERATE_ASSET\n}\n\nenum GradeRange {\n  K_2\n  GRADE_3_5\n  GRADE_6_8\n  GRADE_9_12\n  UNDERGRADUATE\n  GRADUATE\n}\n\nenum RigorLevel {\n  OBSERVATION\n  QUALITATIVE\n  QUANTITATIVE\n}\n\nenum MathLevel {\n  NONE\n  ARITHMETIC\n  ALGEBRA\n  CALCULUS\n}\n\nenum ScaffoldingLevel {\n  HIGH\n  MEDIUM\n  LOW\n}\n\nmodel LearningExperience {\n  id       String @id @default(cuid())\n  tenantId String\n\n  // Links to existing Module (optional, for backward compatibility)\n  moduleId String? @unique\n  module   Module? @relation(fields: [moduleId], references: [id], onDelete: SetNull)\n\n  // Core content\n  title     String\n  domain    ModuleDomain\n  conceptId String?\n\n  // Intent (embedded JSON for simplicity)\n  intentProblem        String\n  intentMotivation     String\n  intentMisconceptions Json // string[]\n  targetGrades         Json // GradeRange[]\n\n  // Curriculum alignment\n  curriculumAlignment Json? // CurriculumAlignment[]\n\n  // Grade adaptations (JSON array of GradeAdaptation)\n  gradeAdaptations Json // GradeAdaptation[]\n\n  // Simulation reference with versioning\n  simulationManifestId String?\n  simulationManifest   SimulationManifest? @relation(\"ExperienceSimulation\", fields: [simulationManifestId], references: [id], onDelete: SetNull)\n  simulationVersion    String? // Track simulation version for compatibility\n\n  // Animation reference with versioning\n  animationManifestId String?\n  animationManifest   AnimationManifest? @relation(\"ExperienceAnimation\", fields: [animationManifestId], references: [id], onDelete: SetNull)\n  animationVersion    String? // Track animation version for compatibility\n\n  // Assessment configuration (embedded)\n  assessmentConfig Json // CBMAssessmentConfig\n\n  // Metadata\n  status               ExperienceStatus @default(DRAFT)\n  version              Int              @default(1)\n  estimatedTimeMinutes Int              @default(30)\n  createdBy            String\n  lastEditedBy         String?\n  publishedAt          DateTime?\n  createdAt            DateTime         @default(now())\n  updatedAt            DateTime         @updatedAt\n\n  // AI & Guardrails metadata\n  promptHash      String? // Hash of refined prompt used for generation\n  riskLevel       RiskLevel @default(LOW)\n  confidenceScore Float? // AI confidence score (0-1)\n\n  // Relations\n  claims                    LearningClaim[]\n  evidences                 LearningEvidence[]\n  experienceTasks           ExperienceTask[]\n  validations               ValidationRecord[]\n  revisions                 ExperienceRevision[]\n  events                    ExperienceEvent[]\n  validationRecordExtendeds ValidationRecordExtended[]\n  reviewQueues              ReviewQueue[]\n  reviewDecisions           ReviewDecision[]\n  experienceAnalytics       ExperienceAnalytics?\n  experienceAutoRefinements ExperienceAutoRefinement[]\n  claimExamples             ClaimExample[]\n  claimSimulations          ClaimSimulation[]\n  claimAnimations           ClaimAnimation[]\n\n  // Auto-Revision relationships\n  abExperiments        ABExperiment[]\n  driftSignals         DriftSignal[]\n  regenerationInsights RegenerationInsight[]\n\n  @@index([tenantId, status])\n  @@index([tenantId, domain])\n  @@index([createdBy])\n  @@index([tenantId, riskLevel])\n  @@index([promptHash])\n}\n\nmodel LearningClaim {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  claimRef   String // e.g., \"C1\", \"C2\"\n  text       String\n  bloomLevel ContentStudioBloomLevel\n  orderIndex Int\n\n  // Prerequisites (JSON array of claim refs from other experiences)\n  prerequisites Json? // string[]\n\n  // Grade-specific overrides (JSON)\n  gradeOverrides Json? // ClaimOverride[]\n\n  // Content needs analysis (JSON) - NEW\n  contentNeeds Json? // { examples: {...}, simulation: {...}, animation: {...} }\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations - NEW\n  examples       ClaimExample[]\n  simulations    ClaimSimulation[]\n  animations     ClaimAnimation[]\n  evidences      LearningEvidence[] // Phase 1: Evidence bundle relation\n  evidenceBundle EvidenceBundleMetadata? // Phase 1: Bundle metadata (1:1)\n\n  @@unique([experienceId, claimRef])\n  @@index([experienceId])\n}\n\nmodel LearningEvidence {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  evidenceRef String // e.g., \"E1\", \"E2\"\n  claimRef    String // Links to which claim\n\n  // Source identity (Phase 1 additions)\n  sourceType            EvidenceSourceType\n  sourceUrl             String?\n  sourceTitle           String\n  sourcePublisher       String?\n  sourcePublicationDate DateTime?\n\n  // Content (Phase 1 additions)\n  excerpt        String? // Direct quote or excerpt\n  structuredFact Json? // Machine-parseable fact representation\n\n  // Legacy fields (to be migrated)\n  type        String? // prediction_vs_outcome, parameter_targeting, etc. (legacy)\n  description String? // (legacy - use excerpt instead)\n  observables Json? // Observable[] (legacy)\n\n  // Provenance (Phase 1 additions)\n  supportKind      SupportKind             @default(SUPPORTS)\n  credibilityScore Float?                  @db.Real // 0.0 - 1.0\n  retrievedAt      DateTime                @default(now())\n  freshnessStatus  EvidenceFreshnessStatus @default(UNKNOWN)\n\n  // Verification (Phase 1 additions)\n  verificationState  EvidenceVerificationState @default(UNVERIFIED)\n  contradictionNotes String?\n\n  // Relation to claim (for cascade purposes)\n  claim LearningClaim? @relation(fields: [experienceId, claimRef], references: [experienceId, claimRef])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([experienceId, evidenceRef])\n  @@index([experienceId])\n  @@index([claimRef])\n  @@index([sourceType])\n  @@index([freshnessStatus])\n}\n\n// =============================================================================\n// Evidence Bundle Metadata (Phase 1 - Task 1.5)\n// =============================================================================\n\nmodel EvidenceBundleMetadata {\n  id String @id @default(cuid())\n\n  // Aggregated metrics\n  bundleConfidence      Float\n  coverageScore         Float\n  contradictionDetected Boolean                 @default(false)\n  freshnessOverall      EvidenceFreshnessStatus @default(UNKNOWN)\n  evidenceCount         Int                     @default(0)\n\n  // Source distribution\n  primarySourceTypes String[] // EvidenceSourceType[]\n\n  // Generation metadata\n  generatedAt     DateTime  @default(now())\n  regeneratedAt   DateTime?\n  generationJobId String?\n\n  // Relation to claim (compound key for 1:1 relation)\n  claimRef     String         @unique\n  experienceId String\n  claim        LearningClaim? @relation(fields: [experienceId, claimRef], references: [experienceId, claimRef])\n\n  // JSON cache of full bundle (for quick retrieval)\n  bundleCache Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([experienceId, claimRef])\n  @@index([bundleConfidence])\n  @@index([freshnessOverall])\n}\n\nmodel ExperienceTask {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  taskRef     String // e.g., \"T1\", \"T2\"\n  type        String // prediction, simulation, explanation, construction\n  claimRef    String\n  evidenceRef String\n  prompt      String\n  orderIndex  Int\n\n  // Type-specific config (JSON)\n  config Json // PredictionConfig | SimulationConfig | etc.\n\n  // Grade-specific overrides\n  gradeOverrides Json? // TaskOverride[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([experienceId, taskRef])\n  @@index([experienceId])\n}\n\nmodel ValidationRecord {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Five Pillars scores (0-100)\n  authorityScore     Int\n  accuracyScore      Int\n  usefulnessScore    Int\n  harmlessnessScore  Int\n  accessibilityScore Int\n  gradefitScore      Int\n\n  overallStatus ValidationStatus\n\n  // Detailed issues (JSON)\n  issues      Json // ValidationIssue[]\n  suggestions Json? // string[]\n\n  validatedAt DateTime @default(now())\n\n  @@index([experienceId])\n}\n\nmodel AIGenerationLog {\n  id           String  @id @default(cuid())\n  tenantId     String\n  userId       String\n  experienceId String?\n\n  operation    AIOperation\n  provider     String // \"openai\", \"anthropic\", \"local\"\n  model        String // \"gpt-4\", \"claude-3.5-sonnet\"\n  modelVersion String? // Model version for auditability\n\n  // Token usage\n  inputTokens  Int\n  outputTokens Int\n  costUsd      Float\n  latencyMs    Int\n\n  // Result\n  success      Boolean\n  errorMessage String?\n\n  // Request/response (for debugging, optional)\n  promptHash  String? // Hash of refined prompt\n  requestHash String? // Hash of input for dedup\n\n  // Guardrails metadata\n  guardrailsVersion String? // Version of guardrails applied\n  riskLevel         RiskLevel @default(LOW)\n  confidenceScore   Float? // AI confidence (0-1)\n\n  createdAt DateTime @default(now())\n\n  @@index([tenantId, createdAt])\n  @@index([userId, createdAt])\n  @@index([experienceId])\n  @@index([promptHash])\n}\n\n// =============================================================================\n// Experience Revisions & Events (for audit trail)\n// =============================================================================\n\nenum AuthorType {\n  HUMAN\n  AI_ASSISTED\n  AI_GENERATED\n}\n\nmodel ExperienceRevision {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  version    Int\n  diff       Json // JSON patch or full snapshot\n  authorType AuthorType\n  authorId   String\n  promptHash String? // If AI-assisted\n\n  createdAt DateTime @default(now())\n\n  @@index([experienceId, version])\n  @@index([experienceId, createdAt])\n}\n\nenum ExperienceEventType {\n  CREATED\n  UPDATED\n  VALIDATED\n  PUBLISHED\n  UNPUBLISHED\n  ARCHIVED\n  CONTENT_CHANGED\n  CLAIMS_GENERATED\n  GRADE_ADAPTED\n  REFINED\n  REVIEW_SUBMITTED\n  REVIEW_DECISION\n  SIMULATION_LINKED\n  SIMULATION_UNLINKED\n  ANALYTICS_VIEWED\n  ANALYTICS_UPDATED\n}\n\nmodel ExperienceEvent {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  eventType ExperienceEventType\n  actorId   String\n  metadata  Json? // Event-specific data\n\n  createdAt DateTime @default(now())\n\n  @@index([experienceId, eventType])\n  @@index([experienceId, createdAt])\n}\n\n// =============================================================================\n// Simulation Manifest Extensions (for versioning & safety)\n// =============================================================================\n\nenum SimulationManifestStatus {\n  DRAFT\n  REVIEW\n  ACTIVE\n  DEPRECATED\n}\n\nmodel SimulationManifestVersion {\n  id                 String             @id @default(cuid())\n  manifestId         String\n  simulationManifest SimulationManifest @relation(\"SimulationManifestVersions\", fields: [manifestId], references: [id], onDelete: Cascade)\n\n  version             String\n  manifestJson        Json // Full manifest at this version\n  safetyConstraints   Json // Safety rules\n  pedagogicalTags     Json // Pedagogy metadata\n  instrumentationPlan Json // Telemetry plan\n\n  status          SimulationManifestStatus @default(DRAFT)\n  riskLevel       RiskLevel                @default(LOW)\n  confidenceScore Float?\n\n  createdBy String\n  createdAt DateTime @default(now())\n\n  @@unique([manifestId, version])\n  @@index([manifestId, status])\n}\n\n// Add relation to SimulationManifest\nmodel SimulationManifestExtension {\n  id                 String             @id\n  simulationManifest SimulationManifest @relation(\"SimulationManifestExtensions\", fields: [id], references: [id], onDelete: Cascade)\n\n  metadata Json? // Additional extension metadata\n}\n\nmodel SimulationLinkAudit {\n  id                   String             @id @default(cuid())\n  experienceId         String\n  simulationManifestId String\n  simulationManifest   SimulationManifest @relation(\"SimulationLinkAudits\", fields: [simulationManifestId], references: [id], onDelete: Cascade)\n\n  action        String // \"linked\", \"unlinked\", \"version_changed\"\n  beforeVersion String?\n  afterVersion  String?\n  actorId       String\n\n  createdAt DateTime @default(now())\n\n  @@index([experienceId, createdAt])\n  @@index([simulationManifestId, createdAt])\n}\n\n// =============================================================================\n// Animation Manifest (first-class visual artifact)\n// =============================================================================\n\nenum AnimationManifestStatus {\n  DRAFT\n  REVIEW\n  ACTIVE\n  DEPRECATED\n}\n\nmodel AnimationManifest {\n  id          String          @id // Stable manifest ID generated from concept\n  tenantId    String\n  domain      AnimationDomain\n  version     String\n  title       String\n  description String?\n  module      Module?         @relation(fields: [moduleId], references: [id], onDelete: SetNull)\n  moduleId    String?\n  manifest    Json // Full AnimationManifest payload\n  createdAt   DateTime        @default(now())\n  updatedAt   DateTime        @updatedAt\n\n  experiences LearningExperience[]        @relation(\"ExperienceAnimation\")\n  versions    AnimationManifestVersion[]  @relation(\"AnimationManifestVersions\")\n  extension   AnimationManifestExtension? @relation(\"AnimationManifestExtensions\")\n  linkAudits  AnimationLinkAudit[]        @relation(\"AnimationLinkAudits\")\n  artifacts   ArtifactManifest[]          @relation(\"ArtifactAnimation\")\n\n  @@index([tenantId, domain])\n  @@index([tenantId, moduleId])\n}\n\nmodel AnimationManifestVersion {\n  id                String            @id @default(cuid())\n  manifestId        String\n  animationManifest AnimationManifest @relation(\"AnimationManifestVersions\", fields: [manifestId], references: [id], onDelete: Cascade)\n\n  version           String\n  manifestJson      Json // Full manifest at this version\n  styleConstraints  Json // Style/presentation rules\n  accessibilityTags Json // A11y metadata\n  renderingPlan     Json // Rendering specifications\n\n  status          AnimationManifestStatus @default(DRAFT)\n  riskLevel       RiskLevel               @default(LOW)\n  confidenceScore Float?\n\n  createdBy String\n  createdAt DateTime @default(now())\n\n  @@unique([manifestId, version])\n  @@index([manifestId, status])\n}\n\nmodel AnimationManifestExtension {\n  id                String            @id\n  animationManifest AnimationManifest @relation(\"AnimationManifestExtensions\", fields: [id], references: [id], onDelete: Cascade)\n\n  metadata Json? // Additional extension metadata\n}\n\nmodel AnimationLinkAudit {\n  id                  String            @id @default(cuid())\n  experienceId        String\n  animationManifestId String\n  animationManifest   AnimationManifest @relation(\"AnimationLinkAudits\", fields: [animationManifestId], references: [id], onDelete: Cascade)\n\n  action        String // \"linked\", \"unlinked\", \"version_changed\"\n  beforeVersion String?\n  afterVersion  String?\n  actorId       String\n\n  createdAt DateTime @default(now())\n\n  @@index([experienceId, createdAt])\n  @@index([animationManifestId, createdAt])\n}\n\n// =============================================================================\n// AI Prompt Cache (for reuse & cost optimization)\n// =============================================================================\n\nmodel AIPromptCache {\n  id       String @id @default(cuid())\n  tenantId String\n\n  rawIntentHash     String @unique // Hash of raw user input\n  flowType          String // \"concept_generation\", \"simulation_generation\", \"refinement\"\n  refinedPrompt     String // Cleaned & enriched prompt\n  guardrailsVersion String // Version of guardrails applied\n\n  // Metadata\n  domain     String?\n  gradeRange String?\n  riskLevel  RiskLevel @default(LOW)\n\n  // Linked outputs\n  aiOutputIds Json // Array of AIGenerationLog IDs\n\n  // TTL\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([tenantId, rawIntentHash])\n  @@index([tenantId, flowType])\n  @@index([expiresAt])\n}\n\n// =============================================================================\n// Validation Extensions (for caching & determinism)\n// =============================================================================\n\nmodel ValidationRecordExtended {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Input hash for cache key\n  inputHash         String // Hash of experience content + simulation version\n  validatorsVersion String // Version of validators used\n\n  // Five Pillars scores (0-100)\n  authorityScore     Int\n  accuracyScore      Int\n  usefulnessScore    Int\n  harmlessnessScore  Int\n  accessibilityScore Int\n  gradefitScore      Int\n\n  overallStatus ValidationStatus\n\n  // Detailed checks with metadata\n  checks      Json // ValidationCheck[] with per-check metadata\n  issues      Json // ValidationIssue[]\n  suggestions Json? // string[]\n\n  // Simulation health\n  simulationHealthReport Json?\n\n  validatedAt DateTime @default(now())\n\n  @@index([experienceId, inputHash])\n  @@index([experienceId, validatedAt])\n}\n\n// =============================================================================\n// Human-in-the-Loop (HITL) Review System\n// =============================================================================\n\nenum ReviewerRole {\n  SME // Subject Matter Expert\n  PEDAGOGY // Pedagogy Reviewer\n  SAFETY // Safety Reviewer\n  ADMIN // Admin Override\n}\n\nenum ReviewDecisionType {\n  APPROVE\n  REJECT\n  REQUEST_CHANGES\n  ESCALATE\n}\n\nmodel ReviewQueue {\n  id           String             @id @default(cuid())\n  tenantId     String\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  queuedAt   DateTime  @default(now())\n  priority   Int       @default(0) // Higher = more urgent\n  assignedTo String? // Reviewer user ID\n  assignedAt DateTime?\n\n  // Context\n  riskLevel     RiskLevel\n  triggerReason String // \"high_risk\", \"low_confidence\", \"policy_violation\"\n  metadata      Json?\n\n  @@index([tenantId, assignedTo])\n  @@index([tenantId, queuedAt])\n  @@index([experienceId])\n}\n\nmodel ReviewDecision {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  reviewerId   String\n  reviewerRole ReviewerRole\n  decision     ReviewDecisionType\n  rationale    String // Mandatory explanation\n  changes      Json? // Suggested or applied changes\n\n  createdAt DateTime @default(now())\n\n  @@index([experienceId, createdAt])\n  @@index([reviewerId, createdAt])\n}\n\n// =============================================================================\n// Analytics & Regeneration\n// =============================================================================\n\nmodel ExperienceAnalytics {\n  id           String             @id @default(cuid())\n  experienceId String             @unique\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Engagement metrics\n  viewCount       Int   @default(0)\n  completionCount Int   @default(0)\n  completionRate  Float @default(0)\n  avgTimeMinutes  Float @default(0)\n  dropOffRate     Float @default(0)\n\n  // Simulation metrics\n  simulationStarts Int @default(0)\n  simulationAborts Int @default(0)\n  simulationErrors Int @default(0)\n\n  // Trend windows (JSON arrays)\n  trends7d  Json? // 7-day trend data\n  trends28d Json? // 28-day trend data\n\n  // Anomaly flags\n  hasEngagementDrift Boolean @default(false)\n  hasQualityIssues   Boolean @default(false)\n\n  updatedAt DateTime @updatedAt\n  createdAt DateTime @default(now())\n\n  @@index([experienceId])\n}\n\nmodel ExperienceAutoRefinement {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Source analytics snapshot\n  analyticsSnapshot Json\n  triggerReason     String // \"low_engagement\", \"high_abort_rate\", \"aging_simulation\"\n\n  // Regenerated candidate\n  candidateExperienceId String?\n  appliedGuardrails     Json\n  aiCompletionId        String?\n\n  // Status\n  status     String    @default(\"pending\") // pending, reviewed, accepted, rejected\n  reviewedBy String?\n  reviewedAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  driftSignal         DriftSignal?         @relation(name: \"DriftSignal_AutoRefinement\")\n  regenerationInsight RegenerationInsight? @relation(name: \"RegenerationInsight_AutoRefinement\")\n\n  @@index([experienceId])\n  @@index([status])\n}\n\n// =============================================================================\n// Evidence-Based Content Models (Claim-Linked Content)\n// =============================================================================\n\nmodel ClaimExample {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n  claimRef     String\n  claim        LearningClaim      @relation(fields: [experienceId, claimRef], references: [experienceId, claimRef], onDelete: Cascade)\n\n  // Manifest reference (source of truth) - Phase 2\n  manifestId      String // References ArtifactManifest\n  manifestVersion String\n\n  // Materialized content (derived from manifest)\n  title       String\n  description String\n  content     Json // { problemStatement?, solution, keyPoints: string[], realWorldConnection? }\n\n  // Example family classification - Phase 2\n  exampleFamily String @default(\"worked-solution\") // 'real-world' | 'analogy' | 'worked-solution' | 'counterexample' | 'case-study'\n\n  // Legacy fields (maintained for compatibility)\n  type       String // \"REAL_WORLD\" | \"PROBLEM_SOLVING\" | \"ANALOGY\" | \"CASE_STUDY\"\n  difficulty String @default(\"INTERMEDIATE\") // BEGINNER | INTERMEDIATE | ADVANCED\n  orderIndex Int\n\n  // Quality - Phase 2\n  validationStatus String @default(\"pending\") // pending | valid | invalid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([experienceId, claimRef])\n  @@index([type])\n  @@index([exampleFamily])\n  @@index([manifestId])\n}\n\nmodel ClaimSimulation {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n  claimRef     String\n  claim        LearningClaim      @relation(fields: [experienceId, claimRef], references: [experienceId, claimRef], onDelete: Cascade)\n\n  simulationManifestId String\n  simulationManifest   SimulationManifest @relation(fields: [simulationManifestId], references: [id])\n\n  interactionType  String // \"parameter_exploration\" | \"prediction\" | \"construction\"\n  goal             String\n  successCriteria  Json // { rmse?: string, maxAttempts?: number, timeLimit?: number }\n  estimatedMinutes Int    @default(10)\n\n  createdAt DateTime @default(now())\n\n  @@unique([experienceId, claimRef])\n  @@index([experienceId])\n  @@index([simulationManifestId])\n}\n\nmodel ClaimAnimation {\n  id           String             @id @default(cuid())\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n  claimRef     String\n  claim        LearningClaim      @relation(fields: [experienceId, claimRef], references: [experienceId, claimRef], onDelete: Cascade)\n\n  // Manifest reference (source of truth) - Phase 2\n  manifestId      String // References ArtifactManifest\n  manifestVersion String\n\n  // Variant support - Phase 2 (allow multiple animations per claim)\n  variantKey String  @default(\"primary\") // 'primary', 'simplified', 'advanced', etc.\n  isPrimary  Boolean @default(true)\n\n  // Rendered configuration (derived from manifest)\n  title       String\n  description String\n  type        String // \"2d\" | \"3d\" | \"timeline\"\n  duration    Int // seconds\n  config      Json // { keyframes, timeline, controls, sceneGraph }\n\n  // Quality - Phase 2\n  validationStatus String @default(\"pending\") // pending | valid | invalid\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Changed from unique on claim to unique on claim+variant\n  @@unique([experienceId, claimRef, variantKey])\n  @@index([experienceId])\n  @@index([isPrimary])\n  @@index([manifestId])\n}\n\n// =============================================================================\n// Auto-Revision and A/B Testing Enhancements\n// ============================================================================\n\nmodel ABExperiment {\n  id           String             @id @default(cuid())\n  tenantId     String\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Version information\n  controlVersion   Int\n  treatmentVersion Int\n\n  // Experiment status\n  status String @default(\"draft\") // \"draft\", \"running\", \"completed\", \"winner_promoted\", \"failed\"\n\n  // Sample sizes\n  controlSampleSize   Int @default(0)\n  treatmentSampleSize Int @default(0)\n\n  // Metrics (JSON storage for flexibility)\n  controlMetrics   Json @default(\"{}\")\n  treatmentMetrics Json @default(\"{}\")\n\n  // Statistical results\n  pValue           Float?\n  confidenceLower  Float?\n  confidenceUpper  Float?\n  effectSize       Float?\n  winner           String? // \"control\", \"treatment\", \"inconclusive\"\n  statisticalPower Float?\n\n  // Timestamps\n  createdAt   DateTime  @default(now())\n  startedAt   DateTime?\n  completedAt DateTime?\n\n  // Metadata\n  notes    String?\n  priority Int     @default(0)\n\n  assignments  ABExperimentAssignment[]\n  observations ABExperimentObservation[]\n\n  @@index([tenantId, status])\n  @@index([experienceId])\n  @@index([status, createdAt])\n}\n\nmodel ABExperimentAssignment {\n  id           String       @id @default(cuid())\n  experimentId String\n  experiment   ABExperiment @relation(fields: [experimentId], references: [id], onDelete: Cascade)\n  tenantId     String\n  userId       String\n  variant      String\n  assignedAt   DateTime     @default(now())\n  lastSeenAt   DateTime     @default(now())\n  metadata     Json?\n\n  @@unique([experimentId, userId])\n  @@index([tenantId, variant])\n  @@index([experimentId, variant])\n}\n\nmodel ABExperimentObservation {\n  id            String       @id @default(cuid())\n  experimentId  String\n  experiment    ABExperiment @relation(fields: [experimentId], references: [id], onDelete: Cascade)\n  tenantId      String\n  userId        String\n  variant       String\n  sessionId     String?\n  assetId       String?\n  metricValue   Float\n  completed     Boolean?\n  masteryScore  Float?\n  feedbackScore Float?\n  metadata      Json?\n  observedAt    DateTime     @default(now())\n\n  @@index([experimentId, variant])\n  @@index([tenantId, observedAt])\n  @@index([experimentId, userId])\n}\n\nmodel DriftSignal {\n  id           String             @id @default(cuid())\n  tenantId     String\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Signal information\n  signalType String // \"engagement_drop\", \"high_abort_rate\", \"low_completion\", \"low_mastery\", \"negative_feedback\"\n  severity   String // \"low\", \"medium\", \"high\"\n  metric     String\n  value      Float\n  threshold  Float\n\n  // AI analysis\n  recommendation String\n  confidence     Float?\n  context        Json? // Additional context for the signal\n\n  // Status\n  status String @default(\"detected\") // \"detected\", \"acknowledged\", \"addressed\", \"false_positive\"\n\n  // Timestamps\n  detectedAt     DateTime  @default(now())\n  acknowledgedAt DateTime?\n  addressedAt    DateTime?\n\n  // Relationships\n  autoRefinementId String?                   @unique\n  autoRefinement   ExperienceAutoRefinement? @relation(name: \"DriftSignal_AutoRefinement\", fields: [autoRefinementId], references: [id])\n\n  @@index([tenantId, experienceId, status])\n  @@index([signalType, severity])\n  @@index([detectedAt])\n}\n\nmodel RegenerationInsight {\n  id           String             @id @default(cuid())\n  tenantId     String\n  experienceId String\n  experience   LearningExperience @relation(fields: [experienceId], references: [id], onDelete: Cascade)\n\n  // Insight classification\n  category        String // \"content_difficulty\", \"content_clarity\", \"simulation_complexity\", \"task_alignment\", \"grade_level\"\n  issue           String\n  suggestedAction String\n  priority        Int // 1-10, higher = more urgent\n\n  // Evidence and analysis\n  evidence   Json // Supporting data for the insight\n  confidence Float? // AI confidence in the insight\n\n  // Status tracking\n  status String @default(\"identified\") // \"identified\", \"analyzed\", \"addressed\", \"rejected\"\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  autoRefinementId String?                   @unique\n  autoRefinement   ExperienceAutoRefinement? @relation(name: \"RegenerationInsight_AutoRefinement\", fields: [autoRefinementId], references: [id])\n\n  @@index([tenantId, experienceId, category])\n  @@index([priority, status])\n  @@index([createdAt])\n}\n\nmodel AutoRevisionConfig {\n  id       String @id @default(cuid())\n  tenantId String @unique\n\n  // Configuration settings\n  enabled                    Boolean @default(true)\n  driftCheckIntervalHours    Int     @default(6)\n  maxConcurrentRegenerations Int     @default(3)\n  minSampleSize              Int     @default(100)\n  significanceThreshold      Float   @default(0.05)\n\n  // Thresholds\n  completionRateThreshold   Float @default(0.6)\n  abortRateThreshold        Float @default(0.3)\n  averageTimeSpentThreshold Float @default(5.0) // minutes\n  masteryRateThreshold      Float @default(0.7)\n  feedbackScoreThreshold    Float @default(3.0) // out of 5\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Metadata\n  updatedBy String?\n  notes     String?\n}\n\nmodel AutoRevisionMetrics {\n  id       String @id @default(cuid())\n  tenantId String\n\n  // Metrics snapshot\n  date DateTime @default(now())\n\n  // Drift detection metrics\n  driftSignalsDetected Int @default(0)\n  experiencesMonitored Int @default(0)\n  highSeveritySignals  Int @default(0)\n\n  // Regeneration metrics\n  regenerationsQueued          Int   @default(0)\n  regenerationsCompleted       Int   @default(0)\n  regenerationsFailed          Int   @default(0)\n  averageProcessingTimeMinutes Float @default(0)\n\n  // A/B testing metrics\n  abExperimentsCreated     Int   @default(0)\n  abExperimentsCompleted   Int   @default(0)\n  averageTestDurationHours Float @default(0)\n  improvementRate          Float @default(0) // Percentage of improvements\n\n  // Performance metrics\n  averageEngagementImprovement Float @default(0)\n  averageCompletionImprovement Float @default(0)\n  averageMasteryImprovement    Float @default(0)\n\n  // System health\n  queueLength    Int @default(0)\n  processingJobs Int @default(0)\n  failedJobs24h  Int @default(0)\n\n  @@unique([tenantId, date])\n  @@index([date])\n}\n\n// =============================================================================\n// Gamification – Badge catalogue, earned achievements, and user points\n// =============================================================================\n\n/// Badge definition (tenant-scoped catalogue of available badges).\nmodel Badge {\n  id          String   @id @default(cuid())\n  tenantId    String\n  name        String\n  description String\n  icon        String\n  category    String   @default(\"LEARNING\") // \"LEARNING\" | \"SOCIAL\" | \"ACHIEVEMENT\" | \"STREAK\"\n  criteria    String // JSON: { type, threshold, customRule? }\n  isActive    Boolean  @default(true)\n  points      Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  earned BadgeEarned[]\n\n  @@index([tenantId])\n  @@index([tenantId, isActive])\n}\n\n/// Earned badge / achievement record linking a user to a badge.\nmodel BadgeEarned {\n  id       String   @id @default(cuid())\n  tenantId String\n  userId   String\n  badgeId  String\n  badge    Badge    @relation(fields: [badgeId], references: [id], onDelete: Cascade)\n  earnedAt DateTime @default(now())\n\n  @@unique([tenantId, userId, badgeId])\n  @@index([tenantId, userId])\n  @@index([tenantId, badgeId])\n}\n\n/// Aggregated point totals and level for a user within a tenant.\nmodel UserPoints {\n  id          String   @id @default(cuid())\n  tenantId    String\n  userId      String\n  totalPoints Int      @default(0)\n  level       Int      @default(1)\n  updatedAt   DateTime @updatedAt\n\n  @@unique([tenantId, userId])\n  @@index([tenantId, totalPoints(sort: Desc)])\n}\n\n// =============================================================================\n// Device Token Registry – first-class push-notification device management\n// =============================================================================\n\n/// Registered push-notification device or web-push subscription for a user.\nmodel DeviceToken {\n  id        String   @id @default(cuid())\n  tenantId  String\n  userId    String\n  /// Raw FCM / APNs token, or a unique identifier for web push.\n  token     String   @unique\n  platform  String // \"ios\" | \"android\" | \"web\"\n  /// Web-push: subscription endpoint URL.\n  endpoint  String?\n  /// Web-push: VAPID p256dh key (base64url).\n  p256dhKey String?\n  /// Web-push: VAPID auth key (base64url).\n  authKey   String?\n  isActive  Boolean  @default(true)\n  lastSeen  DateTime @default(now())\n  createdAt DateTime @default(now())\n\n  @@index([tenantId, userId])\n  @@index([tenantId, userId, isActive])\n}\n\n// =============================================================================\n// Kernel Plugin Registry (persistent storage for registered domain kernels)\n// =============================================================================\n\nmodel KernelPlugin {\n  id           String              @id @default(cuid())\n  tenantId     String\n  pluginId     String              @unique\n  name         String\n  version      String\n  description  String?\n  author       String?\n  kernelType   String\n  capabilities String              @default(\"[]\") // JSON array\n  dependencies String? // JSON object\n  // Digital signature fields for kernel marketplace trust\n  signature    String? // Base64-encoded signature\n  publicKey    String? // Public key used for verification\n  algorithm    String?             @default(\"ed25519\") // Signing algorithm used\n  signedAt     DateTime? // When the kernel was signed\n  signerKeyId  String? // Key identifier for the signing key\n  codeHash     String? // Hash of the kernel code for integrity verification\n  publishedAt  DateTime? // When kernel was published to marketplace\n  createdAt    DateTime            @default(now())\n  updatedAt    DateTime            @updatedAt\n  reviews      MarketplaceReview[]\n\n  @@index([tenantId, kernelType])\n  @@index([tenantId])\n}\n\n// =============================================================================\n// Marketplace Review Workflow\n// =============================================================================\n\nmodel MarketplaceReview {\n  id               String         @id @default(cuid())\n  kernelId         String\n  submitterId      String\n  reviewerId       String?\n  status           ReviewStatus   @default(PENDING)\n  priority         ReviewPriority @default(MEDIUM)\n  submittedAt      DateTime       @default(now())\n  assignedAt       DateTime?\n  completedAt      DateTime?\n  criteria         String? // JSON\n  comments         String?\n  requestedChanges String? // JSON\n  kernel           KernelPlugin   @relation(fields: [kernelId], references: [id])\n\n  @@index([kernelId])\n  @@index([reviewerId])\n  @@index([status])\n  @@index([priority])\n}\n\n// =============================================================================\n// Stripe Connect Integration\n// =============================================================================\n\nmodel StripeAccount {\n  id                    String              @id @default(cuid())\n  userId                String              @unique\n  accountId             String              @unique\n  status                StripeAccountStatus @default(PENDING)\n  country               String\n  email                 String\n  chargesEnabled        Boolean             @default(false)\n  payoutsEnabled        Boolean             @default(false)\n  platformFeePercent    Float               @default(10.0)\n  onboardingCompletedAt DateTime?\n  createdAt             DateTime            @default(now())\n  updatedAt             DateTime            @updatedAt\n\n  @@index([accountId])\n  @@index([status])\n}\n\n// =============================================================================\n// Automation Rules (content studio experience triggers)\n// =============================================================================\n\nmodel AutomationRule {\n  id           String   @id @default(cuid())\n  tenantId     String\n  experienceId String\n  name         String\n  description  String?\n  trigger      String // JSON: { type, conditions }\n  action       String // JSON: { type, params }\n  enabled      Boolean  @default(true)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@index([tenantId, experienceId])\n  @@index([tenantId, enabled])\n}\n\n// =============================================================================\n// Canonical Content Asset Model (P1.1)\n// =============================================================================\n\nenum ContentAssetType {\n  EXPLAINER // Learning experience / explainer content\n  MODULE // Curriculum module\n  EXAMPLE_SET // Collection of worked examples\n  SIMULATION // Interactive simulation\n  ANIMATION // Visual animation sequence\n  ASSESSMENT // Quiz / assessment instrument\n  PATHWAY // Learning pathway / sequence\n  REFERENCE_PACK // Supplementary reference material\n}\n\nenum ContentAssetStatus {\n  DRAFT // Initial authoring state\n  VALIDATING // Validation in progress\n  REVIEW // Awaiting human review\n  APPROVED // Review passed, ready to publish\n  PUBLISHED // Live and discoverable\n  ARCHIVED // Retired from discovery\n}\n\nenum ContentBlockType {\n  TEXT_EXPLAINER // Prose explanation block\n  WORKED_EXAMPLE // Single worked example\n  DATA_TABLE // Tabular data block\n  VISUAL_SEQUENCE // Image or diagram sequence\n  SIMULATION_ENTRY // Embedded simulation reference\n  ANIMATION_ENTRY // Embedded animation reference\n  QUESTION_SET // Assessment question group\n  TASK // Learner task / activity\n  REFLECTION // Reflective prompt\n  HINT // Scaffolding hint\n  TUTOR_PROMPT // AI tutor conversation prompt\n  EVIDENCE_CAPTURE // Evidence collection block\n}\n\nenum ArtifactManifestType {\n  WORKED_EXAMPLE // Manifest for worked examples\n  SIMULATION // Manifest for interactive simulations\n  ANIMATION // Manifest for animations\n  ASSESSMENT // Manifest for assessment instruments\n}\n\nmodel ContentAsset {\n  id       String @id @default(cuid())\n  tenantId String\n\n  // Identity\n  slug      String\n  title     String\n  assetType ContentAssetType\n  domain    ModuleDomain\n  conceptId String?\n\n  // Current state\n  status         ContentAssetStatus @default(DRAFT)\n  currentVersion Int                @default(1)\n  qualityScore   Float? // Aggregate quality score (0-1)\n  reviewState    String? // Current review disposition (JSON)\n\n  // Discovery\n  semanticIndexStatus  String? // \"pending\" | \"indexed\" | \"stale\"\n  recommendationStatus String? // \"pending\" | \"computed\" | \"stale\"\n  searchableText       String? // Denormalized text for full-text search\n  tags                 Json? // string[] for categorization\n\n  // Grade & difficulty\n  targetGrades    Json // GradeRange[]\n  difficultyLevel String? // Freeform difficulty descriptor\n\n  // Provenance\n  authorId     String\n  lastEditedBy String?\n  publishedAt  DateTime?\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  // AI metadata\n  promptHash      String?\n  riskLevel       RiskLevel @default(LOW)\n  confidenceScore Float?\n\n  // Legacy migration links (nullable, for backfill only)\n  legacyModuleId     String? @unique\n  legacyExperienceId String? @unique\n\n  // Relations\n  revisions         ContentAssetRevision[]\n  blocks            ContentBlock[]\n  artifactManifests ArtifactManifest[]\n  semanticChunks    SemanticChunk[]\n  sourceEdges       RecommendationEdge[]   @relation(\"sourceEdges\")\n  targetEdges       RecommendationEdge[]   @relation(\"targetEdges\")\n\n  @@unique([tenantId, slug])\n  @@index([tenantId, assetType, status])\n  @@index([tenantId, domain])\n  @@index([tenantId, status])\n  @@index([authorId])\n  @@index([tenantId, semanticIndexStatus])\n  @@index([legacyModuleId])\n  @@index([legacyExperienceId])\n}\n\nmodel ContentAssetRevision {\n  id      String       @id @default(cuid())\n  assetId String\n  asset   ContentAsset @relation(fields: [assetId], references: [id], onDelete: Cascade)\n\n  // Version tracking\n  version    Int\n  changeNote String?\n  changeDiff Json? // Structured diff from previous version\n  snapshot   Json // Full content snapshot at this version\n\n  // Quality at revision time\n  qualityScore Float?\n  validationId String? // Reference to validation record\n\n  // Provenance\n  createdBy String\n  createdAt DateTime @default(now())\n\n  @@unique([assetId, version])\n  @@index([assetId])\n}\n\nmodel ContentBlock {\n  id      String       @id @default(cuid())\n  assetId String\n  asset   ContentAsset @relation(fields: [assetId], references: [id], onDelete: Cascade)\n\n  // Block identity\n  blockRef   String // \"B1\", \"B2\", etc.\n  blockType  ContentBlockType\n  orderIndex Int\n\n  // Content\n  title   String?\n  payload Json // Block-type-specific content\n\n  // Relations to evidence & claims\n  claimRefs    Json? // string[] linking to claim references\n  evidenceRefs Json? // string[] linking to evidence references\n\n  // Metadata\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([assetId, blockRef])\n  @@index([assetId, orderIndex])\n  @@index([assetId, blockType])\n}\n\nmodel ArtifactManifest {\n  id      String       @id @default(cuid())\n  assetId String\n  asset   ContentAsset @relation(fields: [assetId], references: [id], onDelete: Cascade)\n\n  // Manifest identity\n  manifestType ArtifactManifestType\n  version      String // Semantic version of the manifest\n  claimRef     String? // Which claim this artifact serves\n\n  // Content\n  manifest Json // Full artifact manifest payload\n  schema   String? // Schema version for validation\n\n  // First-class manifest references (for simulations and animations)\n  simulationManifestId String?\n  simulationManifest   SimulationManifest? @relation(\"ArtifactSimulation\", fields: [simulationManifestId], references: [id], onDelete: SetNull)\n  animationManifestId  String?\n  animationManifest    AnimationManifest?  @relation(\"ArtifactAnimation\", fields: [animationManifestId], references: [id], onDelete: SetNull)\n\n  // Quality & validation\n  isValid          Boolean @default(false)\n  validationErrors Json? // ValidationIssue[] from last check\n\n  // Provenance\n  generatedBy  String? // \"ai\" | \"human\" | \"hybrid\"\n  generationId String? // Link to generation request\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@index([assetId, manifestType])\n  @@index([assetId, claimRef])\n  @@index([simulationManifestId])\n  @@index([animationManifestId])\n}\n\n// =============================================================================\n// P2.1 – Semantic Chunking & Embedding Pipeline\n// =============================================================================\n\nenum ChunkSource {\n  BLOCK // Extracted from ContentBlock payload\n  CLAIM // Extracted from a learning claim\n  MANIFEST // Extracted from an artifact manifest\n  METADATA // Extracted from asset metadata (title, tags, etc.)\n}\n\nenum EmbeddingStatus {\n  PENDING // Chunk created, embedding not yet generated\n  PROCESSING // Embedding generation in progress (Java service)\n  READY // Embedding vector available\n  FAILED // Embedding generation failed\n  STALE // Source content changed, re-embedding required\n}\n\nmodel SemanticChunk {\n  id      String       @id @default(cuid())\n  assetId String\n  asset   ContentAsset @relation(fields: [assetId], references: [id], onDelete: Cascade)\n\n  // Chunk identity\n  chunkRef    String // Deterministic ref e.g. \"blk-intro:0\", \"claim-C1\"\n  source      ChunkSource\n  sourceRef   String // ID of the source (blockId, claimId, manifestId)\n  sequenceIdx Int // Position within the source for ordered chunks\n\n  // Text content\n  text        String // Plain-text chunk content\n  tokenCount  Int // Approximate token count\n  contentHash String // SHA-256 of text, for dedup/staleness detection\n\n  // Embedding state\n  embeddingStatus EmbeddingStatus @default(PENDING)\n\n  // Optional metadata\n  domain    String?\n  claimRefs Json? // string[] of claim refs covered\n  tags      Json? // string[] tags for faceted retrieval\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Embedding relation\n  embedding EmbeddingVector?\n\n  @@unique([assetId, chunkRef])\n  @@index([assetId, source])\n  @@index([assetId, embeddingStatus])\n  @@index([contentHash])\n}\n\nmodel EmbeddingVector {\n  id      String        @id @default(cuid())\n  chunkId String        @unique\n  chunk   SemanticChunk @relation(fields: [chunkId], references: [id], onDelete: Cascade)\n\n  // Vector data\n  vector     Bytes // Raw embedding vector (float32 array as binary)\n  dimensions Int // Vector dimensionality (e.g., 1536 for ada-002)\n  model      String // Model used (e.g., \"text-embedding-ada-002\")\n\n  // Quality metadata\n  generatedAt  DateTime @default(now())\n  generationMs Int? // Time taken to generate in ms\n  jobId        String? // Java processing job reference\n\n  @@index([chunkId])\n}\n\n// =============================================================================\n// P2.3 — Recommendation Edges\n// =============================================================================\n\nenum RecommendationEdgeType {\n  PREREQUISITE\n  FOLLOW_UP\n  RELATED\n  ALTERNATIVE\n  DEEPER_DIVE\n}\n\nenum RecommendationSource {\n  RULE_BASED\n  SEMANTIC\n  OUTCOME_AWARE\n  MANUAL\n}\n\nmodel RecommendationEdge {\n  id String @id @default(cuid())\n\n  // Source → Target direction\n  sourceAssetId String\n  sourceAsset   ContentAsset @relation(\"sourceEdges\", fields: [sourceAssetId], references: [id], onDelete: Cascade)\n  targetAssetId String\n  targetAsset   ContentAsset @relation(\"targetEdges\", fields: [targetAssetId], references: [id], onDelete: Cascade)\n\n  // Edge properties\n  edgeType   RecommendationEdgeType\n  source     RecommendationSource   @default(RULE_BASED)\n  weight     Float                  @default(1.0) // Ranking weight [0..1]\n  confidence Float? // Confidence score\n  reason     String? // Human-readable explanation\n  metadata   Json? // Extra context\n\n  // Lifecycle\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([sourceAssetId, targetAssetId, edgeType])\n  @@index([sourceAssetId, edgeType])\n  @@index([targetAssetId, edgeType])\n  @@index([sourceAssetId, weight])\n}\n\n// =============================================================================\n// P3.1 — Generation Planner & Request Model\n// =============================================================================\n\nenum GenerationRequestStatus {\n  DRAFT\n  PLANNING\n  PLANNED\n  EXECUTING\n  COMPLETED\n  FAILED\n  CANCELLED\n}\n\nenum GenerationJobStatus {\n  PENDING\n  RUNNING\n  COMPLETED\n  FAILED\n  CANCELLED\n}\n\nenum GenerationJobType {\n  CLAIM\n  EXPLAINER\n  WORKED_EXAMPLE\n  SIMULATION\n  ANIMATION\n  ASSESSMENT\n  EVALUATION\n}\n\nenum ReviewPath {\n  AUTO_PUBLISH\n  HUMAN_REVIEW\n  EXPERT_REVIEW\n}\n\nenum RiskLevel {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nmodel GenerationRequest {\n  id       String @id @default(cuid())\n  tenantId String\n\n  // Request metadata\n  title         String\n  description   String?\n  domain        String\n  conceptId     String?\n  targetGrades  Json? // String[]\n  requestedBy   String // authorId\n  requestConfig Json?\n\n  // Planning output\n  status          GenerationRequestStatus @default(DRAFT)\n  plannedAssets   Json? // Array of planned asset descriptors\n  artifactNeeds   Json? // { explainers: N, examples: N, simulations: N, ... }\n  riskLevel       RiskLevel               @default(LOW)\n  riskFactors     Json? // String[] of risk reasons\n  reviewPath      ReviewPath              @default(HUMAN_REVIEW)\n  estimatedCost   Json? // { tokens: N, embeddingCalls: N, ... }\n  routingDecision Json?\n\n  // Execution tracking\n  totalJobs     Int @default(0)\n  completedJobs Int @default(0)\n  failedJobs    Int @default(0)\n\n  // Lifecycle\n  plannedAt   DateTime?\n  startedAt   DateTime?\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  // Relations\n  jobs            GenerationJob[]\n  provenanceNodes ProvenanceNode[]\n\n  @@index([tenantId, status])\n  @@index([tenantId, requestedBy])\n  @@index([tenantId, domain])\n}\n\nmodel ProvenanceNode {\n  id                  String @id @default(cuid())\n  generationRequestId String\n  tenantId            String\n\n  // Artifact being traced\n  claimRef      String\n  kind          String // claim, example, simulation, animation, evidence_item, validation_result\n  assertionText String @db.Text\n\n  // Source context\n  model             String\n  modelVersion      String\n  promptHash        String\n  sourceDocumentRef String?\n  context           Json? // domain, gradeLevel, etc.\n\n  // Metadata\n  generatedAt   DateTime @default(now())\n  schemaVersion String   @default(\"1.0\")\n\n  // Lifecycle\n  createdAt DateTime @default(now())\n\n  // Relations\n  generationRequest GenerationRequest @relation(fields: [generationRequestId], references: [id], onDelete: Cascade)\n\n  @@index([generationRequestId, tenantId])\n  @@index([tenantId, claimRef])\n  @@index([tenantId, kind])\n}\n\nmodel GenerationJob {\n  id        String            @id @default(cuid())\n  requestId String\n  request   GenerationRequest @relation(fields: [requestId], references: [id], onDelete: Cascade)\n\n  // Job specification\n  jobType     GenerationJobType\n  targetRef   String? // Reference to planned asset/artifact\n  inputPrompt String? // Generation prompt or config\n  parameters  Json? // Job-specific parameters\n\n  // Status\n  status   GenerationJobStatus @default(PENDING)\n  progress Int                 @default(0) // 0-100\n\n  // Output\n  outputAssetId String? // Resulting ContentAsset id\n  outputData    Json? // Raw generation output\n  diagnostics   Json? // Warnings, quality notes\n\n  // Error handling\n  errorMessage String?\n  retryCount   Int     @default(0)\n  maxRetries   Int     @default(3)\n\n  // Timing\n  startedAt   DateTime?\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  replayManifests GenerationReplayManifest[]\n\n  @@index([requestId, status])\n  @@index([requestId, jobType])\n}\n\nmodel GenerationReplayManifest {\n  id              String        @id @default(cuid())\n  generationJobId String\n  generationJob   GenerationJob @relation(fields: [generationJobId], references: [id], onDelete: Cascade)\n\n  // Seed information for deterministic replay\n  seed       String\n  seedSource String // 'deterministic' | 'random' | 'provided'\n\n  // Job metadata\n  jobType     String\n  inputParams Json\n\n  // Output data for reproducibility verification\n  outputData Json?\n  replayable Boolean @default(true)\n\n  // Timing\n  generatedAt DateTime @default(now())\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([generationJobId])\n  @@index([seedSource])\n  @@index([generatedAt])\n}\n\n// =============================================================================\n// P3.3 – Evaluation & Guardrail Scorecards\n// =============================================================================\n\nenum EvaluationStatus {\n  PENDING\n  RUNNING\n  PASSED\n  FAILED\n  SKIPPED\n}\n\nenum PublishRecommendation {\n  AUTO_PUBLISH\n  MANUAL_REVIEW\n  BLOCK\n}\n\nmodel EvaluationRecord {\n  id       String @id @default(cuid())\n  tenantId String\n\n  // Links\n  assetId             String? // ContentAsset id if already created\n  generationJobId     String? // GenerationJob id\n  generationRequestId String?\n\n  // Scores per dimension (0.0 – 1.0)\n  coherenceScore        Float?\n  completenessScore     Float?\n  safetyScore           Float?\n  accessibilityScore    Float?\n  manifestValidityScore Float?\n\n  // Aggregate\n  overallScore   Float?\n  status         EvaluationStatus      @default(PENDING)\n  recommendation PublishRecommendation @default(MANUAL_REVIEW)\n\n  // Findings\n  issues      Json? // EvaluationIssue[]\n  diagnostics Json?\n\n  errorMessage String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, status])\n  @@index([tenantId, assetId])\n  @@index([generationJobId])\n  @@index([generationRequestId])\n}\n\n// =============================================================================\n// P3.4 – Generation Review Decision\n// =============================================================================\n\nenum GenerationReviewDecisionStatus {\n  PENDING\n  APPROVED\n  REJECTED\n  REGENERATION_REQUESTED\n}\n\nmodel GenerationReviewDecision {\n  id       String @id @default(cuid())\n  tenantId String\n\n  requestId String\n\n  // Decision\n  status       GenerationReviewDecisionStatus @default(PENDING)\n  reviewedBy   String? // userId of reviewer\n  decisionNote String?\n\n  // Regeneration\n  regenerateJobIds Json? // String[] job ids to regenerate\n\n  reviewedAt DateTime?\n  createdAt  DateTime  @default(now())\n  updatedAt  DateTime  @updatedAt\n\n  @@index([tenantId, requestId])\n  @@index([tenantId, status])\n}\n\n// =============================================================================\n// P4.1 – Explorer Telemetry Events\n// =============================================================================\n\nenum ExplorerEventType {\n  IMPRESSION\n  CLICK\n  QUERY_REFORMULATION\n  ASSET_START\n  ASSET_COMPLETE\n  NEXT_STEP_SELECT\n  RANKING_FEEDBACK\n}\n\nmodel ExplorerEvent {\n  id        String  @id @default(cuid())\n  tenantId  String\n  userId    String?\n  sessionId String?\n\n  eventType ExplorerEventType\n\n  // Context\n  query     String?\n  assetId   String?\n  assetType String?\n  position  Int? // rank position in results\n  score     Float? // ranking score at time of event\n\n  // Feedback\n  feedbackLabel String? // \"relevant\" | \"not_relevant\" | \"helpful\" | etc.\n  feedbackScore Float?\n\n  // Raw\n  metadata Json?\n\n  occurredAt DateTime @default(now())\n\n  @@index([tenantId, eventType])\n  @@index([tenantId, assetId])\n  @@index([tenantId, userId])\n  @@index([occurredAt])\n}\n\n// =============================================================================\n// P4.3 – Regeneration Candidates\n// =============================================================================\n\nenum RegenerationTrigger {\n  POOR_DISCOVERY_PERFORMANCE\n  POOR_LEARNING_OUTCOMES\n  MISCONCEPTION_PATTERN\n  STALE_CURRICULUM\n  SAFETY_CONCERN\n  LOW_EVALUATION_SCORE\n  MANUAL_FLAGGED\n}\n\nenum RegenerationCandidateStatus {\n  OPEN\n  QUEUED\n  IN_PROGRESS\n  RESOLVED\n  DISMISSED\n}\n\nmodel RegenerationCandidate {\n  id       String @id @default(cuid())\n  tenantId String\n\n  assetId   String\n  assetType String?\n\n  trigger  RegenerationTrigger\n  severity RiskLevel           @default(MEDIUM)\n\n  // Evidence\n  reason   String\n  evidence Json? // supporting telemetry / eval data\n  priority Int    @default(50) // 0-100, higher wins\n\n  status RegenerationCandidateStatus @default(OPEN)\n\n  // Action taken\n  generationRequestId String?\n  resolvedBy          String?\n  resolvedAt          DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, status])\n  @@index([tenantId, assetId])\n  @@index([tenantId, trigger])\n}\n\n// =============================================================================\n// Content Evaluation – Remediation Queue\n// =============================================================================\n\nenum RemediationStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETED\n  FAILED\n  DISMISSED\n}\n\nmodel RemediationQueue {\n  id           String @id @default(cuid())\n  tenantId     String\n  experienceId String\n  artifactId   String\n  contentType  String\n\n  // Evaluation context\n  trustScore       Float\n  publishDecision  String\n  triggerReason    String\n  remediationNotes String?\n\n  // Processing status\n  status      RemediationStatus @default(PENDING)\n  assignedTo  String? // AI agent or worker ID\n  startedAt   DateTime?\n  completedAt DateTime?\n\n  // Retry tracking\n  attemptCount  Int       @default(0)\n  lastAttemptAt DateTime?\n  nextAttemptAt DateTime?\n\n  // Result\n  resultArtifactId   String?\n  resultValidationId String?\n\n  metadata Json? // { originalScores, appliedChanges, validationResults }\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, status])\n  @@index([tenantId, experienceId])\n  @@index([tenantId, artifactId])\n  @@index([status, nextAttemptAt])\n  @@index([createdAt])\n}\n\n// =============================================================================\n// Stripe Tax – Transaction Records for Compliance Reporting\n// =============================================================================\n\nmodel TaxTransaction {\n  id       String @id @default(cuid())\n  tenantId String\n\n  // Stripe references\n  stripeTaxCalculationId String\n  stripeTaxTransactionId String? @unique\n  stripePaymentIntentId  String?\n\n  // Transaction details\n  amountCents    Int\n  taxAmountCents Int\n  currency       String  @default(\"usd\")\n  country        String\n  state          String?\n  postalCode     String?\n\n  // Tax breakdown (stored as JSON for flexibility)\n  taxBreakdown Json? // Array of { jurisdiction, ratePercentage, taxType, amountCents }\n\n  // Compliance\n  reference  String? // External reference (invoice number, etc.)\n  reportedAt DateTime?\n  reportId   String? // Link to generated compliance report\n\n  metadata Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, createdAt])\n  @@index([tenantId, country, state])\n  @@index([tenantId, reportId])\n  @@index([stripeTaxTransactionId])\n  @@index([createdAt])\n}\n\n// =============================================================================\n// Payout Failure Notifications\n// =============================================================================\n\nenum PayoutNotificationStatus {\n  PENDING\n  SENT\n  DELIVERED\n  FAILED\n}\n\nmodel PayoutNotification {\n  id             String @id @default(cuid())\n  tenantId       String\n  payoutId       String\n  stripePayoutId String\n  userId         String\n\n  notificationType String // \"payout_failed\", \"payout_created\", \"payout_delayed\"\n  status           PayoutNotificationStatus @default(PENDING)\n\n  // Delivery channels\n  emailSent   Boolean   @default(false)\n  emailSentAt DateTime?\n  pushSent    Boolean   @default(false)\n  pushSentAt  DateTime?\n\n  // Content\n  subject        String?\n  body           String?\n  failureReason  String?\n  actionRequired Boolean @default(false)\n\n  metadata Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, userId])\n  @@index([tenantId, status])\n  @@index([stripePayoutId])\n  @@index([createdAt])\n}\n"
}

